import { HandicapScheme } from './handicap-scheme';
import { Fleet, getFleetName } from 'app/club-tenant/model/fleet';

export type ScoringConfiguration = LevelRatingConfiguration | HandicapConfiguration;

export interface BaseScoringConfiguration {
   id: string;
   name: string;
   fleet: Fleet;
}

export interface LevelRatingConfiguration extends BaseScoringConfiguration {
   type: 'LevelRating';
   handicapScheme: 'Level Rating';
}

export interface HandicapConfiguration extends BaseScoringConfiguration {
   type: 'Handicap';
   handicapScheme: Exclude<HandicapScheme, 'Level Rating'>;
}

export function getConfigName(hcapScheme: HandicapScheme, fleet?: Fleet) {
   if (!fleet) {
      return hcapScheme;
   }

   switch (fleet.type) {
      case 'BoatClass':
         return getFleetName(fleet);
      case 'Tag':
         return getFleetName(fleet);
      case 'GeneralHandicap':
      case 'HandicapRange':
         return hcapScheme;
   }

}

import type { Handicap } from 'app/scoring/model/handicap';
import type { PersonalHandicapBand } from 'app/scoring/model/personal-handicap';

export interface Boat {
  id: string;
  sailNumber: number;
  boatClass: string;
  name: string;
  helm: string;
  crew: string;
  isClub: boolean;
  /** Boat-level handicaps (e.g. IRC, Personal) when the club supports them */
  handicaps?: Handicap[];
  /** Personal handicap band used to derive Personal handicap from PY */
  personalHandicapBand?: PersonalHandicapBand;
}

import { Handicap } from 'app/scoring/model/handicap';

export interface BoatClass {
   id: string;
   name: string;
   handicaps: Handicap[];
}

import { HandicapScheme } from 'app/scoring/model/handicap-scheme';

export interface GeneralHandicapFleet {
   type: 'GeneralHandicap';
   id: string;
   name: 'General Handicap';
}

export interface BoatClassFleet {
   type: 'BoatClass';
   id: string;
   boatClassId: string;
}

export interface HandicapRangeFleet {
   type: 'HandicapRange';
   id: string;
   name: string;
   scheme: HandicapScheme;
   min: number;
   max: number;
}

export interface TagFleet {
   type: 'Tag';
   id: string;
   name: string; // e.g. "Novice"
   value: string; // The tag string to match, e.g. "Novice"
}

export type Fleet = GeneralHandicapFleet | BoatClassFleet | HandicapRangeFleet | TagFleet;

export function getFleetName(fleet: Fleet): string {
   switch (fleet.type) {
      case 'GeneralHandicap':
         return 'General Handicap';
      case 'BoatClass':
         return fleet.boatClassId;
      case 'HandicapRange':
         return fleet.name;
      case 'Tag':
         return fleet.name;
   }
}

import { ChangeDetectionStrategy, Component, computed, input } from '@angular/core';
import { MatCardModule } from '@angular/material/card';
import { MatListModule } from '@angular/material/list';
import { Race } from 'app/race-calender';
import { ResolvedRaceCompetitor } from 'app/results-input';

interface BoatSeriesSummary {
   seriesName: string;
   raceCount: number;
}

interface BoatEntry {
   boatId: string;
   boatClass: string;
   sailNumber: string;
   helm: string;
   seriesSummaries: BoatSeriesSummary[];
}

@Component({
   selector: 'app-boat-entry-summary',
   imports: [MatListModule],
   template: `
    <mat-list class="dense-list">
      @for (boat of boatEntries(); track boat.boatId) {
         <mat-list-item>
            <span matListItemTitle>
              <span class=gap>{{ boat.boatClass }} {{ boat.sailNumber }}</span>
               <span>{{ boat.helm }}</span>
            </span>
            <span matListItemLine>
         @for (summary of boat.seriesSummaries; track summary.seriesName) {
            <span class=gap>{{ summary.seriesName}} {{ summary.raceCount }} race(s)</span>
         }
      </span>
      </mat-list-item>
      }
   </mat-list>
  `,
   styles: [`
      .gap {
         margin-right: 12px;
      }
  `],
   changeDetection: ChangeDetectionStrategy.OnPush,
})
export class BoatEntrySummaryComponent {
   competitors = input.required<ResolvedRaceCompetitor[]>();
   races = input.required<Race[]>();

   boatEntries = computed(() => {
      const competitors = this.competitors();
      const races = this.races();
      const racesById = new Map(races.map(r => [r.id, r]));

      const boats = new Map<string, { comp: ResolvedRaceCompetitor, series: Map<string, number>; }>();

      for (const comp of competitors) {
         const boatId = `${comp.boatClass}-${comp.sailNumber}`;
      if (!boats.has(boatId)) {
        boats.set(boatId, { comp, series: new Map<string, number>() });
      }
      const race = racesById.get(comp.raceId);
      if (race) {
        const seriesMap = boats.get(boatId)!.series;
        seriesMap.set(race.seriesName, (seriesMap.get(race.seriesName) || 0) + 1);
      }
    }

    return Array.from(boats.values()).map(({ comp, series }) => ({
      boatId: `${comp.boatClass}-${comp.sailNumber}`,
      boatClass: comp.boatClass,
      sailNumber: comp.sailNumber,
      helm: comp.helm,
      seriesSummaries: Array.from(series.entries()).map(([seriesName, raceCount]) => ({
        seriesName,
        raceCount,
      })).sort((a, b) => a.seriesName.localeCompare(b.seriesName)),
    })).sort((a,b) => a.boatClass.localeCompare(b.boatClass) || a.sailNumber.toString().localeCompare(b.sailNumber.toString()));
  });
}

import { Injectable } from '@angular/core';
import { Boat } from '../model/boat';
import { Handicap } from 'app/scoring/model/handicap';
import { HandicapScheme } from 'app/scoring/model/handicap-scheme';
import { getHandicapValue } from 'app/scoring/model/handicap';
import { normaliseString } from 'app/shared/utils/string-utils';
import { parseCsv, toCsv } from 'app/shared/utils/csv';
import { getHandicapSchemeMetadata } from 'app/scoring/model/handicap-scheme-metadata';
import type { PersonalHandicapBand } from 'app/scoring/model/personal-handicap';

const BASE_COLUMNS = ['id', 'boatClass', 'sailNumber', 'helm', 'crew', 'name', 'isClub', 'personalHandicapBand'] as const;
const ALLOWED_PERSONAL_BANDS = new Set<PersonalHandicapBand>([
  'Band0',
  'Band1',
  'Band2',
  'Band3',
  'Band4',
  'Band5',
]);

export interface BoatsCsvParseResult {
  boats: Partial<Boat>[];
  errors: string[];
}

@Injectable({ providedIn: 'root' })
export class BoatsCsvService {
  buildCsv(boats: Boat[], schemes: HandicapScheme[]): string {
    const handicapColumns = schemes.map(s => this.handicapColumn(s));
    const columns = [...BASE_COLUMNS, ...handicapColumns];
    const rows = boats.map(boat => {
      const row: Record<string, string> = {
        id: boat.id,
        boatClass: boat.boatClass ?? '',
        sailNumber: String(boat.sailNumber ?? ''),
        helm: boat.helm ?? '',
        crew: boat.crew ?? '',
        name: boat.name ?? '',
        isClub: boat.isClub ? 'true' : 'false',
        personalHandicapBand: boat.personalHandicapBand ?? '',
      };
      for (const scheme of schemes) {
        const value = getHandicapValue(boat.handicaps, scheme);
        row[this.handicapColumn(scheme)] = value == null ? '' : String(value);
      }
      return row;
    });
    return toCsv(columns, rows);
  }

  parseCsv(content: string, schemes: HandicapScheme[]): BoatsCsvParseResult {
    const parsed = parseCsv(content);
    const errors: string[] = [...parsed.errors];
    const headerColumns = parsed.header;
    if (headerColumns.length === 0) {
      return { boats: [], errors: parsed.errors };
    }
    const requiredColumns = [...BASE_COLUMNS];
    const handicapColumns = schemes.map(s => this.handicapColumn(s));
    const expectedColumns = [...requiredColumns, ...handicapColumns];
    const missing = expectedColumns.filter(c => !headerColumns.includes(c));
    if (missing.length > 0) {
      return { boats: [], errors: [`Missing required columns: ${missing.join(', ')}`] };
    }

    const boats: Partial<Boat>[] = [];
    for (let i = 0; i < parsed.rows.length; i++) {
      const record = parsed.rows[i];
      const rowResult = this.parseBoatRecord(record, schemes, i + 2);
      if (rowResult.error) {
        errors.push(rowResult.error);
      } else if (rowResult.boat) {
        boats.push(rowResult.boat);
      }
    }
    return { boats, errors };
  }

  tripletKey(boat: Pick<Boat, 'boatClass' | 'sailNumber' | 'helm'>): string {
    return `${normaliseString(boat.boatClass)}|${boat.sailNumber}|${normaliseString(boat.helm)}`;
  }

  private parseBoatRecord(
    record: Record<string, string>,
    schemes: HandicapScheme[],
    lineNumber: number
  ): { boat?: Partial<Boat>; error?: string } {
    const rowErrors: string[] = [];
    const boatClass = (record['boatClass'] ?? '').trim();
    const sailRaw = (record['sailNumber'] ?? '').trim();
    const helm = (record['helm'] ?? '').trim();
    const crew = (record['crew'] ?? '').trim();
    const name = (record['name'] ?? '').trim();
    const id = (record['id'] ?? '').trim();
    const isClubRaw = (record['isClub'] ?? '').trim();
    const isClub = this.parseBool(isClubRaw);
    const personalHandicapBandRaw = (record['personalHandicapBand'] ?? '').trim();
    const sailNumber = Number(sailRaw);

    if (!boatClass) rowErrors.push('boatClass is required');
    if (!Number.isFinite(sailNumber) || sailNumber <= 0 || !Number.isInteger(sailNumber)) {
      rowErrors.push('sailNumber must be a positive integer');
    }
    if (isClubRaw && isClub == null) {
      rowErrors.push('isClub must be true/false (also accepts 1/0/yes/no/y/n)');
    }
    if (
      personalHandicapBandRaw &&
      personalHandicapBandRaw.toLowerCase() !== 'unknown' &&
      !ALLOWED_PERSONAL_BANDS.has(personalHandicapBandRaw as PersonalHandicapBand)
    ) {
      rowErrors.push('personalHandicapBand must be one of Band0..Band5 or unknown');
    }

    const isClubBool = isClub ?? false;
    if (!isClubBool && !helm) {
      rowErrors.push('helm is required for non-club boats');
    }

    const handicaps: Handicap[] = [];
    for (const scheme of schemes) {
      const raw = (record[this.handicapColumn(scheme)] ?? '').trim();
      if (!raw) continue;
      const value = Number(raw);
      const meta = getHandicapSchemeMetadata(scheme);
      if (!Number.isFinite(value) || value <= 0) {
        rowErrors.push(`${this.handicapColumn(scheme)} must be a positive number if provided`);
        continue;
      }
      if (value < meta.min || value > meta.max) {
        rowErrors.push(
          `${this.handicapColumn(scheme)} must be between ${meta.min} and ${meta.max}`
        );
        continue;
      }
      handicaps.push({ scheme, value });
    }
    if (rowErrors.length > 0) {
      return {
        error: `Line ${lineNumber}: ${rowErrors.join('; ')}`,
      };
    }

    const band: PersonalHandicapBand | undefined =
      !personalHandicapBandRaw || personalHandicapBandRaw.toLowerCase() === 'unknown'
        ? undefined
        : (personalHandicapBandRaw as PersonalHandicapBand);

    const boat: Partial<Boat> = {
      boatClass,
      sailNumber,
      helm,
      crew,
      name,
      isClub: isClubBool,
      personalHandicapBand: band,
      handicaps,
    };
    if (id) {
      boat.id = id;
    }
    return { boat };
  }

  private parseBool(raw: string): boolean | undefined {
    const norm = raw.trim().toLowerCase();
    if (!norm) return undefined;
    if (norm === 'true' || norm === '1' || norm === 'yes' || norm === 'y') return true;
    if (norm === 'false' || norm === '0' || norm === 'no' || norm === 'n') return false;
    return undefined;
  }

  private handicapColumn(scheme: HandicapScheme): string {
    return `handicap${scheme.replace(/[^a-zA-Z0-9]/g, '')}`;
  }
}

