export interface CsvParseOutput {
  header: string[];
  rows: Record<string, string>[];
  errors: string[];
}

export function parseCsv(text: string): CsvParseOutput {
  const parsedRows = parseRawRows(text);
  if (parsedRows.length === 0) {
    return { header: [], rows: [], errors: ['CSV file is empty.'] };
  }

  const header = parsedRows[0].values.map(v => v.trim());
  const seen = new Set<string>();
  const dupHeaders = header.filter(h => {
    const key = h.toLowerCase();
    if (seen.has(key)) return true;
    seen.add(key);
    return false;
  });
  if (dupHeaders.length > 0) {
    return {
      header: [],
      rows: [],
      errors: [`Duplicate header columns: ${[...new Set(dupHeaders)].join(', ')}`],
    };
  }

  const rows: Record<string, string>[] = [];
  const errors: string[] = [];
  for (let i = 1; i < parsedRows.length; i++) {
    const row = parsedRows[i];
    if (row.values.length > header.length) {
      errors.push(`Line ${row.lineNumber}: too many columns.`);
      continue;
    }
    const out: Record<string, string> = {};
    for (let col = 0; col < header.length; col++) {
      out[header[col]] = row.values[col] ?? '';
    }
    rows.push(out);
  }
  return { header, rows, errors };
}

export function toCsv(columns: string[], rows: Array<Record<string, string>>): string {
  const headerLine = columns.map(csvEscape).join(',');
  const dataLines = rows.map(row => columns.map(c => csvEscape(row[c] ?? '')).join(','));
  return [headerLine, ...dataLines].join('\n');
}

interface ParsedCsvRow {
  values: string[];
  lineNumber: number;
}

function parseRawRows(content: string): ParsedCsvRow[] {
  const rows: ParsedCsvRow[] = [];
  let current = '';
  let row: string[] = [];
  let inQuotes = false;
  let lineNumber = 1;
  let rowStartLine = 1;

  for (let i = 0; i < content.length; i++) {
    const ch = content[i];
    const next = content[i + 1];

    if (ch === '"') {
      if (inQuotes && next === '"') {
        current += '"';
        i++;
      } else {
        inQuotes = !inQuotes;
      }
      continue;
    }

    if (ch === ',' && !inQuotes) {
      row.push(current);
      current = '';
      continue;
    }

    if ((ch === '\n' || ch === '\r') && !inQuotes) {
      if (ch === '\r' && next === '\n') i++;
      row.push(current);
      current = '';
      if (row.some(v => v.length > 0)) {
        rows.push({ values: row, lineNumber: rowStartLine });
      }
      row = [];
      lineNumber++;
      rowStartLine = lineNumber;
      continue;
    }

    current += ch;
  }

  if (current.length > 0 || row.length > 0) {
    row.push(current);
    if (row.some(v => v.length > 0)) {
      rows.push({ values: row, lineNumber: rowStartLine });
    }
  }
  return rows;
}

function csvEscape(value: string): string {
  if (value.includes('"') || value.includes(',') || value.includes('\n') || value.includes('\r')) {
    return `"${value.replace(/"/g, '""')}"`;
  }
  return value;
}

import { ChangeDetectionStrategy, Component, computed, inject, signal } from '@angular/core';
import { MatButtonModule } from '@angular/material/button';
import { MatCheckboxModule } from '@angular/material/checkbox';
import { MAT_DIALOG_DATA, MatDialogModule, MatDialogRef } from '@angular/material/dialog';
import type { Race } from '../../model/race';
import { RaceCalendarStore } from '../../services/full-race-calander';
import { RaceTitlePipe } from 'app/shared/pipes/race-title-pipe';
import { groupBy } from 'app/shared/utils/group-by';

export interface RacePickerDialogData {
  title: string;
  /** Ids selected when the dialog opens. */
  preselectedRaceIds?: string[];
  /** At most this many races (e.g. `1` for scoring sheet). Omit for unlimited. */
  maxSelections?: number;
  /** If true (default), OK stays disabled until at least one race is selected. */
  requireSelection?: boolean;
}

interface DayGroup {
  readonly dateKey: string;
  readonly heading: string;
  readonly races: Race[];
}

function isScheduledToday(race: Race): boolean {
  return new Date(race.scheduledStart).toDateString() === new Date().toDateString();
}

function sortRacesByTimeThenIndex(a: Race, b: Race): number {
  return a.scheduledStart.getTime() - b.scheduledStart.getTime() || a.index - b.index;
}

function dayHeading(d: Date): string {
  return new Intl.DateTimeFormat(undefined, {
    weekday: 'long',
    day: 'numeric',
    month: 'long',
    year: 'numeric',
  }).format(d);
}

@Component({
  selector: 'app-race-picker-dialog',
  template: `
    <h2 mat-dialog-title>{{ data.title }}</h2>
    <mat-dialog-content class="picker-content">
      @if (todayRaces().length === 0 && !showMoreDays() && otherDayGroups().length === 0) {
        <p class="hint">No upcoming races in calendar.</p>
      } @else if (todayRaces().length === 0 && !showMoreDays()) {
        <p class="hint">No races scheduled today.</p>
      }

      @if (todayRaces().length > 0) {
        <h3 class="group-heading">{{ todayHeading() }}</h3>
        @for (race of todayRaces(); track race.id) {
          <mat-checkbox
            class="race-option"
            [checked]="isSelected(race.id)"
            (change)="onToggle(race.id, $event.checked)">
            {{ race | racetitle }}
          </mat-checkbox>
        }
      }

      @if (showMoreDays()) {
        @for (group of otherDayGroups(); track group.dateKey) {
          <h3 class="group-heading">{{ group.heading }}</h3>
          @for (race of group.races; track race.id) {
            <mat-checkbox
              class="race-option"
              [checked]="isSelected(race.id)"
              (change)="onToggle(race.id, $event.checked)">
              {{ race | racetitle }}
            </mat-checkbox>
          }
        }
      }

      @if (!showMoreDays() && otherDayGroups().length > 0) {
        <button type="button" mat-button class="more-dates" (click)="showMoreDays.set(true)">
          More races…
        </button>
      }
    </mat-dialog-content>
    <mat-dialog-actions align="end">
      <button mat-button type="button" (click)="cancel()">Cancel</button>
      <button mat-flat-button color="primary" type="button" [disabled]="!canConfirm()" (click)="confirm()">
        OK
      </button>
    </mat-dialog-actions>
  `,
  styles: `
    .picker-content {
      display: flex;
      flex-direction: column;
      gap: 8px;
      max-height: min(60vh, 520px);
      min-width: min(92vw, 420px);
      overflow-y: auto;
    }
    .hint {
      margin: 0 0 4px;
      color: var(--mat-sys-on-surface-variant, rgba(0, 0, 0, 0.6));
    }
    .group-heading {
      margin: 12px 0 4px;
      font-size: 0.875rem;
      font-weight: 500;
      color: var(--mat-sys-on-surface-variant, rgba(0, 0, 0, 0.7));
    }
    .group-heading:first-of-type {
      margin-top: 0;
    }
    .race-option {
      margin: 2px 0;
      white-space: normal;
      line-height: 1.35;
      display: block;
    }
    .more-dates {
      align-self: flex-start;
      margin-top: 4px;
    }
  `,
  imports: [MatDialogModule, MatButtonModule, MatCheckboxModule, RaceTitlePipe],
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class RacePickerDialog {
  protected readonly data = inject<RacePickerDialogData>(MAT_DIALOG_DATA);
  private readonly dialogRef = inject(MatDialogRef<RacePickerDialog, string[] | undefined>);
  protected readonly raceStore = inject(RaceCalendarStore);

  protected readonly showMoreDays = signal(false);

  private readonly maxSelections = this.data.maxSelections;
  private readonly requireSelection = this.data.requireSelection ?? true;

  private readonly selectedIds = signal<Set<string>>(
    new Set(this.data.preselectedRaceIds?.filter(Boolean) ?? []),
  );

  protected readonly todayRaces = computed(() =>
    this.raceStore.allRaces().filter(isScheduledToday).sort(sortRacesByTimeThenIndex),
  );

  protected readonly todayHeading = computed(() => dayHeading(new Date()));

  protected readonly otherDayGroups = computed((): DayGroup[] => {
    const races = this.raceStore
      .allRaces()
      .filter(r => !isScheduledToday(r))
      .sort(sortRacesByTimeThenIndex);

    const byDay = groupBy(races, race => new Date(race.scheduledStart).toDateString());

    return [...byDay.entries()]
      .sort((a, b) => new Date(a[1][0].scheduledStart).getTime() - new Date(b[1][0].scheduledStart).getTime())
      .map(([dateKey, dayRaces]) => ({
        dateKey,
        heading: dayHeading(dayRaces[0].scheduledStart),
        races: dayRaces,
      }));
  });

  protected isSelected(id: string): boolean {
    return this.selectedIds().has(id);
  }

  protected onToggle(id: string, checked: boolean): void {
    this.selectedIds.update(prev => {
      const next = new Set(prev);
      if (this.maxSelections === 1) {
        next.clear();
        if (checked) {
          next.add(id);
        }
        return next;
      }
      if (checked) {
        if (this.maxSelections != null && next.size >= this.maxSelections) {
          return prev;
        }
        next.add(id);
      } else {
        next.delete(id);
      }
      return next;
    });
  }

  protected canConfirm(): boolean {
    if (!this.requireSelection) {
      return true;
    }
    return this.selectedIds().size > 0;
  }

  protected cancel(): void {
    this.dialogRef.close(undefined);
  }

  protected confirm(): void {
    if (!this.canConfirm()) {
      return;
    }
    this.dialogRef.close([...this.selectedIds()]);
  }
}

import { inject, Injectable } from '@angular/core';
import { SeriesEntryStore } from './series-entry-store';
import { RaceCompetitorStore } from './race-competitor-store';
import { Handicap, getHandicapValue } from 'app/scoring/model/handicap';
import { PersonalHandicapBand } from 'app/scoring/model/personal-handicap';
import { ScoreSmarterError } from 'app/shared/utils/scoresmarter-error';
import { RaceCompetitor } from '../model/race-competitor';
import { SeriesEntry } from '../model/series-entry';
import {
  PerHullIdentity,
  describeIdentity,
  findCollidingEntry,
} from './series-entry-identity';

/**
 * Per-race overrides are now intentionally minimal. Only `crew` may differ
 * between races for the same hull (handled via `RaceCompetitor.crewOverride`).
 * Every other piece of identity / boat / handicap data lives on the
 * `SeriesEntry` and is therefore inherently series-wide.
 */
export type CrewEditScope = 'raceOnly' | 'wholeSeries';

export type EditOperation =
  | { type: 'setHelm'; value: string }
  | { type: 'setCrew'; value: string; scope: CrewEditScope }
  | { type: 'setBoatClass'; value: string }
  | { type: 'setSailNumber'; value: number }
  | { type: 'setHandicap'; scheme: Handicap['scheme']; value: number }
  | { type: 'setPersonalHandicapBand'; band: PersonalHandicapBand | undefined }
  | { type: 'deleteCompetitor' };

export interface EditRaceCompetitorCommand {
  competitorId: string;
  operation: EditOperation;
}

/**
 * Applies edit commands originating from the per-race UI. Logic intentionally
 * isolates per-race scope (only the crew field) from per-hull scope (everything
 * else); see `EditOperation` for the strict allowed shapes.
 */
@Injectable({ providedIn: 'root' })
export class RaceCompetitorEditService {
  private readonly competitors = inject(RaceCompetitorStore);
  private readonly seriesEntries = inject(SeriesEntryStore);

  async apply(command: EditRaceCompetitorCommand): Promise<void> {
    const target = this.competitors.selectedCompetitors().find(c => c.id === command.competitorId);
    if (!target) {
      throw new Error(`Competitor not found: ${command.competitorId}`);
    }
    const entry = this.seriesEntries.selectedEntries().find(e => e.id === target.seriesEntryId);
    if (!entry) {
      throw new Error(`SeriesEntry ${target.seriesEntryId} not found for competitor ${target.id}`);
    }

    switch (command.operation.type) {
      case 'deleteCompetitor':
        await this.deleteCompetitor(target);
        return;
      case 'setCrew':
        await this.applyCrew(target, entry, command.operation);
        return;
      case 'setHelm':
      case 'setBoatClass':
      case 'setSailNumber':
      case 'setHandicap':
      case 'setPersonalHandicapBand':
        await this.applyEntryChange(entry, command.operation);
        return;
    }
  }

  private async applyCrew(
    target: RaceCompetitor,
    entry: SeriesEntry,
    op: Extract<EditOperation, { type: 'setCrew' }>,
  ): Promise<void> {
    const trimmed = op.value.trim();
    if (op.scope === 'raceOnly') {
      // crewOverride === undefined means "use entry crew"; we keep the empty
      // string as an explicit override that clears the entry crew for this race.
      const next = trimmed === (entry.crew ?? '') ? undefined : trimmed;
      if ((target.crewOverride ?? null) === (next ?? null)) return;
      await this.competitors.updateResult(target.id, { crewOverride: next });
      return;
    }

    if ((entry.crew ?? '') !== trimmed) {
      await this.seriesEntries.updateEntry(entry.id, { crew: trimmed });
    }
    // Wholeseries: drop any per-race overrides for this entry that now match
    // the new entry crew. We deliberately do NOT touch overrides that still
    // diverge from the new entry crew.
    const allForEntry = this.competitors.selectedCompetitors().filter(c => c.seriesEntryId === entry.id);
    for (const comp of allForEntry) {
      if (comp.crewOverride !== undefined && comp.crewOverride === trimmed) {
        await this.competitors.updateResult(comp.id, { crewOverride: undefined });
      }
    }
  }

  private async applyEntryChange(
    entry: SeriesEntry,
    op: Exclude<EditOperation, { type: 'setCrew' | 'deleteCompetitor' }>,
  ): Promise<void> {
    // setHelm / setBoatClass / setSailNumber rewrite the per-hull identity
    // tuple and could collide with another existing SeriesEntry. Guard against
    // that here so we never break the "one entry per (helm, class, sail)"
    // invariant via a rename - the user must resolve the duplicate first.
    if (op.type === 'setHelm' || op.type === 'setBoatClass' || op.type === 'setSailNumber') {
      this.assertRenameDoesNotCollide(entry, op);
    }

    const update: Partial<SeriesEntry> = {};
    switch (op.type) {
      case 'setHelm':
        if (entry.helm === op.value) return;
        update.helm = op.value;
        break;
      case 'setBoatClass':
        if (entry.boatClass === op.value) return;
        update.boatClass = op.value;
        break;
      case 'setSailNumber':
        if (entry.sailNumber === op.value) return;
        update.sailNumber = op.value;
        break;
      case 'setHandicap': {
        const current = getHandicapValue(entry.handicaps, op.scheme);
        if (current === op.value) return;
        const without = (entry.handicaps ?? []).filter(h => h.scheme !== op.scheme);
        update.handicaps = [...without, { scheme: op.scheme, value: op.value }];
        break;
      }
      case 'setPersonalHandicapBand':
        if ((entry.personalHandicapBand ?? null) === (op.band ?? null)) return;
        update.personalHandicapBand = op.band;
        break;
    }
    if (Object.keys(update).length > 0) {
      await this.seriesEntries.updateEntry(entry.id, update);
    }
  }

  /**
   * Throws if applying `op` to `entry` would produce a per-hull identity that
   * already exists on a different SeriesEntry in the same series. Excludes
   * the entry being edited itself so a no-op rename is allowed.
   */
  private assertRenameDoesNotCollide(
    entry: SeriesEntry,
    op: Extract<EditOperation, { type: 'setHelm' | 'setBoatClass' | 'setSailNumber' }>,
  ): void {
    const next: PerHullIdentity = {
      helm: op.type === 'setHelm' ? op.value : entry.helm,
      boatClass: op.type === 'setBoatClass' ? op.value : entry.boatClass,
      sailNumber: op.type === 'setSailNumber' ? op.value : entry.sailNumber,
    };
    const sameSeries = this.seriesEntries
      .selectedEntries()
      .filter(e => e.seriesId === entry.seriesId);
    const collision = findCollidingEntry(sameSeries, next, entry.id);
    if (collision) {
      throw new ScoreSmarterError(
        `Cannot rename: another series entry already exists for ` +
        `${describeIdentity(next)} (id ${collision.id}). ` +
        `Delete or merge that entry before renaming.`,
      );
    }
  }

  private async deleteCompetitor(target: RaceCompetitor): Promise<void> {
    await this.competitors.deleteResult(target.id);
    // If no other RaceCompetitor still references the SeriesEntry, drop the
    // entry too so it doesn't haunt the series with a phantom DNC row.
    const stillReferenced = this.competitors
      .selectedCompetitors()
      .some(c => c.id !== target.id && c.seriesEntryId === target.seriesEntryId);
    if (!stillReferenced) {
      await this.seriesEntries.deleteEntry(target.seriesEntryId);
    }
  }
}

import { ChangeDetectionStrategy, Component, computed, inject } from '@angular/core';
import { FormBuilder, ReactiveFormsModule, Validators } from '@angular/forms';
import { MatButtonModule } from '@angular/material/button';
import { MAT_DIALOG_DATA, MatDialogModule, MatDialogRef } from '@angular/material/dialog';
import { MatFormFieldModule } from '@angular/material/form-field';
import { MatInputModule } from '@angular/material/input';
import { MatSelectModule } from '@angular/material/select';
import { ResolvedRaceCompetitor } from 'app/results-input';
import { HandicapScheme } from 'app/scoring/model/handicap-scheme';
import { calculatePersonalHandicapFromPy, PERSONAL_HANDICAP_BANDS, type PersonalHandicapBand } from 'app/scoring/model/personal-handicap';
import { EditRaceCompetitorCommand } from '../../services/race-competitor-edit.service';

type OperationType = EditRaceCompetitorCommand['operation']['type'];

export interface EditRaceCompetitorDialogData {
  /** The race row being edited - identity comes from its SeriesEntry. */
  competitor: ResolvedRaceCompetitor;
}

/**
 * Edit dialog for a single race row.
 *
 * Identity, boat and handicap edits are always applied to the SeriesEntry
 * (per-hull) - there is no per-race scope option for them. Crew is the only
 * field where a per-race override makes sense, so it gets a scope picker
 * (`raceOnly` => `RaceCompetitor.crewOverride`; `wholeSeries` => entry crew).
 */
@Component({
  selector: 'app-edit-race-competitor-dialog',
  imports: [ReactiveFormsModule, MatDialogModule, MatFormFieldModule, MatInputModule, MatSelectModule, MatButtonModule],
  template: `
    <h2 mat-dialog-title>Edit competitor</h2>
    <mat-dialog-content [formGroup]="form" class="edit-dialog-content">
      <mat-form-field appearance="outline">
        <mat-label>Change</mat-label>
        <mat-select formControlName="operation">
          <mat-option value="setHelm">Helm</mat-option>
          <mat-option value="setCrew">Crew</mat-option>
          <mat-option value="setBoatClass">Boat class</mat-option>
          <mat-option value="setSailNumber">Sail number</mat-option>
          <mat-option value="setHandicap">Handicap</mat-option>
          <mat-option value="setPersonalHandicapBand">Personal handicap band</mat-option>
          <mat-option value="deleteCompetitor">Delete competitor</mat-option>
        </mat-select>
      </mat-form-field>

      @if (showHandicap()) {
        <div class="row">
          <mat-form-field appearance="outline">
            <mat-label>Scheme</mat-label>
            <mat-select formControlName="handicapScheme">
              @for (h of availableSchemes(); track h) {
                <mat-option [value]="h">{{ h }}</mat-option>
              }
            </mat-select>
          </mat-form-field>
          <mat-form-field appearance="outline">
            <mat-label>Value</mat-label>
            <input matInput formControlName="handicapValue" type="number" />
          </mat-form-field>
        </div>
      } @else if (showPersonalBand()) {
        <mat-form-field appearance="outline">
          <mat-label>Personal handicap band</mat-label>
          <mat-select formControlName="personalBand">
            <mat-option [value]="null">(none)</mat-option>
            @for (band of personalBands; track band) {
              <mat-option [value]="band">{{ band }}</mat-option>
            }
          </mat-select>
        </mat-form-field>
      } @else if (showText()) {
        <mat-form-field appearance="outline">
          <mat-label>New value</mat-label>
          <input matInput [type]="isSailNumber() ? 'number' : 'text'" formControlName="value" />
        </mat-form-field>
      }

      @if (isCrew()) {
        <mat-form-field appearance="outline">
          <mat-label>Apply to</mat-label>
          <mat-select formControlName="crewScope">
            <mat-option value="raceOnly">This race only</mat-option>
            <mat-option value="wholeSeries">All races for this hull</mat-option>
          </mat-select>
        </mat-form-field>
      } @else if (!isDelete()) {
        <p class="hint">Applies to every race for this hull in the series.</p>
      }
    </mat-dialog-content>
    <mat-dialog-actions align="end">
      <button mat-button type="button" (click)="dialogRef.close()">Cancel</button>
      <button mat-flat-button color="primary" type="button" [disabled]="form.invalid" (click)="submit()">Apply</button>
    </mat-dialog-actions>
  `,
  styles: [`
    .edit-dialog-content { display: flex; flex-direction: column; gap: 8px; min-width: min(92vw, 420px); }
    .row { display: grid; grid-template-columns: 1fr 1fr; gap: 8px; }
    .hint { color: var(--mat-sys-on-surface-variant); margin: 0; font-size: 12px; }
  `],
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class EditRaceCompetitorDialog {
  readonly dialogRef = inject(MatDialogRef<EditRaceCompetitorDialog, EditRaceCompetitorCommand | undefined>);
  private readonly data = inject<EditRaceCompetitorDialogData>(MAT_DIALOG_DATA);
  private readonly fb = inject(FormBuilder);

  readonly form = this.fb.group({
    operation: this.fb.nonNullable.control<OperationType>('setCrew', Validators.required),
    value: this.fb.nonNullable.control<string>(''),
    handicapScheme: this.fb.nonNullable.control<string>(''),
    handicapValue: this.fb.nonNullable.control<number>(0),
    personalBand: this.fb.control<PersonalHandicapBand | null>(null),
    crewScope: this.fb.nonNullable.control<'raceOnly' | 'wholeSeries'>('raceOnly', Validators.required),
  });

  readonly availableSchemes = computed(() => [...new Set(this.data.competitor.handicaps.map(h => h.scheme))].filter(s => s !== 'Personal'));
  readonly personalBands = PERSONAL_HANDICAP_BANDS;

  constructor() {
    this.form.controls.operation.valueChanges.subscribe(op => {
      const current = this.currentValueFor(op);
      this.form.controls.value.setValue(current);
      if (op === 'setHandicap') {
        const first = this.data.competitor.handicaps.find(h => h.scheme !== 'Personal');
        this.form.controls.handicapScheme.setValue(first?.scheme ?? 'PY');
        this.form.controls.handicapValue.setValue(first?.value ?? 0);
      }
      if (op === 'setPersonalHandicapBand') {
        this.form.controls.personalBand.setValue(this.data.competitor.personalHandicapBand ?? null);
      }
      this.syncValidators(op);
    });
    this.form.controls.operation.setValue('setCrew');
  }

  isCrew = () => this.form.controls.operation.value === 'setCrew';
  isDelete = () => this.form.controls.operation.value === 'deleteCompetitor';
  isSailNumber = () => this.form.controls.operation.value === 'setSailNumber';
  showHandicap = () => this.form.controls.operation.value === 'setHandicap';
  showPersonalBand = () => this.form.controls.operation.value === 'setPersonalHandicapBand';
  showText = () => {
    const op = this.form.controls.operation.value;
    return op === 'setHelm' || op === 'setCrew' || op === 'setBoatClass' || op === 'setSailNumber';
  };

  submit(): void {
    const op = this.form.controls.operation.value;
    const value = this.form.controls.value.value.trim();
    let operation: EditRaceCompetitorCommand['operation'];
    switch (op) {
      case 'setHelm':
        operation = { type: op, value };
        break;
      case 'setCrew':
        operation = { type: op, value, scope: this.form.controls.crewScope.value };
        break;
      case 'setBoatClass':
        operation = { type: op, value };
        break;
      case 'setSailNumber':
        operation = { type: op, value: Number(value) };
        break;
      case 'setHandicap': {
        const scheme = this.form.controls.handicapScheme.value as HandicapScheme;
        const handicapValue = Number(this.form.controls.handicapValue.value);
        operation = { type: op, scheme, value: handicapValue };
        break;
      }
      case 'setPersonalHandicapBand':
        operation = { type: op, band: this.form.controls.personalBand.value ?? undefined };
        break;
      default:
        if (!confirm('Delete this competitor from this race?')) return;
        operation = { type: 'deleteCompetitor' };
        break;
    }
    this.dialogRef.close({ competitorId: this.data.competitor.id, operation });
  }

  private currentValueFor(op: OperationType): string {
    switch (op) {
      case 'setHelm':
        return this.data.competitor.helm;
      case 'setCrew':
        return this.data.competitor.crew ?? '';
      case 'setBoatClass':
        return this.data.competitor.boatClass;
      case 'setSailNumber':
        return String(this.data.competitor.sailNumber);
      default:
        return '';
    }
  }

  private syncValidators(op: OperationType): void {
    const value = this.form.controls.value;
    if (op === 'deleteCompetitor' || op === 'setHandicap' || op === 'setPersonalHandicapBand') {
      value.clearValidators();
    } else if (op === 'setSailNumber') {
      value.setValidators([Validators.required, Validators.pattern('^[0-9]+$')]);
    } else if (op === 'setCrew') {
      value.clearValidators();
    } else {
      value.setValidators([Validators.required]);
    }
    value.updateValueAndValidity({ emitEvent: false });

    const hs = this.form.controls.handicapScheme;
    const hv = this.form.controls.handicapValue;
    const pb = this.form.controls.personalBand;
    if (op === 'setHandicap') {
      hs.setValidators([Validators.required]);
      hv.setValidators([Validators.required, Validators.min(1)]);
      pb.clearValidators();
    } else {
      hs.clearValidators();
      hv.clearValidators();
      pb.clearValidators();
    }
    hs.updateValueAndValidity({ emitEvent: false });
    hv.updateValueAndValidity({ emitEvent: false });
    pb.updateValueAndValidity({ emitEvent: false });
  }
}

import { Injectable, inject } from '@angular/core';
import { RaceCalendarStore } from 'app/race-calender';
import { SeriesEntryStore } from 'app/results-input/services/series-entry-store';
import { ScoreSmarterError } from 'app/shared/utils/scoresmarter-error';
import { ClubStore } from '../../club-tenant';
import { Race } from '../../race-calender/model/race';
import { RaceCompetitor } from '../../results-input/model/race-competitor';
import { SeriesEntry } from '../../results-input/model/series-entry';
import { RaceCompetitorStore } from '../../results-input/services/race-competitor-store';
import { Handicap } from 'app/scoring/model/handicap';
import { PersonalHandicapBand } from 'app/scoring/model/personal-handicap';
import { resolveHandicapsForSeries } from './entry-helpers';
import {
  PerHullIdentity,
  describeIdentity,
  detectInRaceConflict,
  EntryConflictReason,
  findAllMatchingEntries,
} from 'app/results-input/services/series-entry-identity';

export interface EntryDetails {
  races: Race[];
  helm: string;
  crew?: string;
  boatClass: string;
  sailNumber: number;
  handicaps?: Handicap[];
  personalHandicapBand?: PersonalHandicapBand;
}

/**
 * A pre-existing race entry that prevents the proposed sign-on. Surfaced to
 * the UI so the user can choose to overwrite (boat-swap) or cancel; never
 * reported when the proposed entry can simply be added.
 */
export interface EntryConflict {
  race: Race;
  reason: EntryConflictReason;
  existingCompetitor: RaceCompetitor;
  existingEntry: SeriesEntry;
}

/**
 * Per-hull SeriesEntry creation.
 *
 * Each unique (boatClass, sailNumber, helm) tuple in a series corresponds to
 * exactly one SeriesEntry. The series-level `entryAlgorithm` only controls
 * how those entries are *merged at scoring time* into competitor groups (see
 * `mergeKeyFor`); it no longer affects how entries are created or how
 * duplicate sign-on is detected. This guarantees per-hull data (handicap,
 * boat class) is never overwritten when one helm sails multiple boats in
 * the same series.
 */
@Injectable({
  providedIn: 'root'
})
export class EntryService {
  private clubStore = inject(ClubStore);
  private raceResultsStore = inject(RaceCompetitorStore);
  private seriesEntryStore = inject(SeriesEntryStore);
  private raceCalanderStore = inject(RaceCalendarStore);

  /** Enter a race
   * throws a ScoreSmarterError exception if any conflict is detected.
   *
   * Callers that want to surface conflicts to the user (boat-swap UX) should
   * call `findEntryConflicts` first and, if appropriate, `swapAndEnter`. This
   * method is a strict guard for any caller that doesn't.
   */
  async enterRaces(details: EntryDetails): Promise<void> {

    const conflicts = this.findEntryConflicts(details);
    if (conflicts.length > 0) {
      throw new ScoreSmarterError(
        `Entry conflict for ${describeIdentity({
          boatClass: details.boatClass,
          sailNumber: details.sailNumber,
          helm: details.helm,
        })}`,
      );
    }

    for (const race of details.races) {
      const series = this.raceCalanderStore.allSeries().find(s => s.id === race.seriesId);
      if (!series) {
        const msg = 'EntryService: Series not found for race: ' + race.toString();
        console.error(msg);
        throw new ScoreSmarterError(msg);
      }

      const handicapsForEntry = resolveHandicapsForSeries(series, {
        boatClassName: details.boatClass,
        handicaps: details.handicaps,
        personalHandicapBand: details.personalHandicapBand,
        personalHandicapUnknown: !details.personalHandicapBand,
      }, this.clubStore.club().classes);

      const seriesEntryId =
        await this.findOrCreateSeriesEntry(race, details, handicapsForEntry);

      const competitor: Partial<RaceCompetitor> = {
        raceId: race.id,
        seriesId: race.seriesId,
        seriesEntryId,
        resultCode: 'NOT FINISHED',
      };

      await this.raceResultsStore.addResult(competitor);
    }
  }

  /**
   * Find every existing race entry that prevents the proposed sign-on across
   * the selected races. Each conflict is reported with its reason (exact-hull
   * duplicate, helm-already-in-race for merged-helm series, hull-already-in-
   * race for merged-hull series) so the caller can present a swap dialog.
   *
   * Joins each per-race competitor row to its SeriesEntry because identity
   * fields (helm/boatClass/sailNumber) live on the entry, not on the race
   * competitor.
   */
  findEntryConflicts(details: EntryDetails): EntryConflict[] {
    const incoming: PerHullIdentity = {
      boatClass: details.boatClass,
      sailNumber: details.sailNumber,
      helm: details.helm,
    };

    const entriesById = new Map(
      this.seriesEntryStore.selectedEntries().map(e => [e.id, e] as const),
    );
    const allComps = this.raceResultsStore.selectedCompetitors();
    const conflicts: EntryConflict[] = [];

    for (const race of details.races) {
      const series = this.raceCalanderStore.allSeries().find(s => s.id === race.seriesId);
      // Default to the strictest strategy if the series can't be located so
      // we never silently downgrade conflict detection.
      const strategy = series?.entryAlgorithm ?? 'classSailNumberHelm';

      for (const comp of allComps) {
        if (comp.raceId !== race.id) continue;
        const entry = entriesById.get(comp.seriesEntryId);
        if (!entry) continue;
        const reason = detectInRaceConflict(entry, incoming, strategy);
        if (reason) {
          conflicts.push({ race, reason, existingCompetitor: comp, existingEntry: entry });
        }
      }
    }

    return conflicts;
  }

  /**
   * Boat-swap path: delete every conflicting race competitor (and any
   * SeriesEntry that becomes orphaned in *this* series as a result), then
   * proceed with the requested entry. The caller is expected to have already
   * obtained the user's consent via the conflict dialog.
   *
   * The deletion is per-race: an existing entry that is also used in OTHER
   * races stays put and only loses its row in the conflicting race(s).
   */
  async swapAndEnter(details: EntryDetails, conflicts: EntryConflict[]): Promise<void> {
    for (const conflict of conflicts) {
      await this.raceResultsStore.deleteResult(conflict.existingCompetitor.id);
    }

    // Re-evaluate after the deletions so we don't sign in twice if the same
    // race appeared in `conflicts` AND another later code path tries to add
    // it again. After the swap there must be no remaining conflicts; if there
    // are, the caller's view of the world was stale and we abort loudly.
    const remaining = this.findEntryConflicts(details);
    if (remaining.length > 0) {
      throw new ScoreSmarterError(
        `Boat swap could not clear all conflicts (${remaining.length} remaining). ` +
        `Refresh and try again.`,
      );
    }

    await this.enterRaces(details);

    // Best-effort cleanup: if the swap left a SeriesEntry with no race
    // competitors anywhere, drop it so it doesn't haunt the entry list. We do
    // this after `enterRaces` so we never delete an entry the new sign-on is
    // about to reuse (findOrCreateSeriesEntry matches on identity, so the
    // entry id we deleted from would only be reused if identity matched the
    // incoming entry — which it can't, since that would have been a
    // `sameEntry` conflict and consumed by `enterRaces` above).
    await this.cleanupOrphanedEntries(conflicts);
  }

  private async cleanupOrphanedEntries(conflicts: EntryConflict[]): Promise<void> {
    const candidateIds = new Set(conflicts.map(c => c.existingEntry.id));
    const stillReferenced = new Set(
      this.raceResultsStore.selectedCompetitors().map(c => c.seriesEntryId),
    );
    for (const entryId of candidateIds) {
      if (!stillReferenced.has(entryId)) {
        try {
          await this.seriesEntryStore.deleteEntry(entryId);
        } catch (err) {
          // Don't fail the whole swap if cleanup fails — the new entry is
          // already in place. Just log so we can spot leaking entries later.
          console.warn(`EntryService: orphaned SeriesEntry cleanup failed for ${entryId}`, err);
        }
      }
    }
  }

  /**
   * Find an existing per-hull SeriesEntry (matched by boatClass + sailNumber +
   * helm) or create one. Updates the entry's handicaps/personalHandicapBand
   * to the latest input so they stay current; identity fields are preserved.
   */
  async findOrCreateSeriesEntry(race: Race, details: EntryDetails, handicaps: Handicap[]): Promise<string> {
    const seriesEntries = this.seriesEntryStore.selectedEntries()
      .filter(e => e.seriesId === race.seriesId);

    const identity: PerHullIdentity = {
      boatClass: details.boatClass,
      sailNumber: details.sailNumber,
      helm: details.helm,
    };
    const matches = findAllMatchingEntries(seriesEntries, identity);

    // Per-hull invariant: at most one SeriesEntry should ever match a given
    // (helm, boatClass, sailNumber). Detecting more than one means a previous
    // write (a rename, a manual Firestore edit, or a pre-refactor merge) has
    // corrupted the dataset. Refuse to write more results against either
    // entry until the duplicate is resolved.
    if (matches.length > 1) {
      throw new ScoreSmarterError(
        `Data integrity error: ${matches.length} SeriesEntries already match ` +
        `${describeIdentity(identity)} in series ${race.seriesId} ` +
        `(ids: ${matches.map(e => e.id).join(', ')}). ` +
        `Resolve the duplicate before continuing.`,
      );
    }

    const existing = matches[0];

    if (existing) {
      const entryUpdate: Partial<SeriesEntry> = {
        handicaps,
        personalHandicapBand: details.personalHandicapBand,
        tags: this.withPersonalBandTag(existing.tags, details.personalHandicapBand),
      };
      // Update crew if a value was provided (stays on the entry).
      if (details.crew !== undefined && details.crew !== existing.crew) {
        entryUpdate.crew = details.crew;
      }
      await this.seriesEntryStore.updateEntry(existing.id, entryUpdate);
      return existing.id;
    }

    console.log(`EntryService: Adding series entry ${race.seriesName} index: ${race.index}`);

    return this.seriesEntryStore.addEntry({
      seriesId: race.seriesId,
      helm: details.helm,
      crew: details.crew,
      boatClass: details.boatClass,
      sailNumber: details.sailNumber,
      handicaps,
      personalHandicapBand: details.personalHandicapBand,
      tags: this.withPersonalBandTag([], details.personalHandicapBand),
    });
  }

  private withPersonalBandTag(tags: string[] | undefined, band: PersonalHandicapBand | undefined): string[] {
    const next = new Set((tags ?? []).filter(t => !t.startsWith('personal-band:')));
    if (band) next.add(`personal-band:${band}`);
    return [...next];
  }
}

import { Component, inject } from '@angular/core';
import { MatButtonModule } from '@angular/material/button';
import { MatDialogModule, MatDialogRef } from '@angular/material/dialog';
import { MatDividerModule } from '@angular/material/divider';
import { MatListModule } from '@angular/material/list';

export type EntryConflictChoice = 'swap' | 'cancel';

/** UI-facing summary of a single conflicting entry. The dialog deliberately
 *  knows nothing about Race/RaceCompetitor/SeriesEntry shapes so it can be
 *  reused outside the entry page if needed. */
export interface EntryConflictSummary {
  raceLabel: string;
  existingLabel: string;
  reasonLabel: string;
}

@Component({
  selector: 'app-entry-conflict-dialog',
  template: `
    <h3 mat-dialog-title>{{ title }}</h3>
    <div mat-dialog-content>
      <p>{{ intro }}</p>
      <mat-list dense>
        @for (c of conflicts; track c.raceLabel + c.existingLabel) {
          <mat-list-item>
            <span matListItemTitle>{{ c.raceLabel }}</span>
            <span matListItemLine>Already entered as {{ c.existingLabel }}</span>
