import { differenceInSeconds } from 'date-fns';
import { deleteField } from 'firebase/firestore';
import { RaceCompetitorStore } from './race-competitor-store';
import { RaceCompetitor } from '../model/race-competitor';
import { ResolvedRaceCompetitor, sortResolvedCompetitors } from '../model/resolved-race-competitor';
import { SeriesEntryStore } from './series-entry-store';
import { resolveStartTimeForEntry } from './race-start-resolver';
import type { RaceStart } from 'app/race-calender/model/race-start';

/**
 * View model used by the manual results table. Adds a derived `correctedTime`
 * to a `ResolvedRaceCompetitor`. Sorting and identity continue to come from
 * the underlying SeriesEntry.
 */
export class ExtendedRaceCompetitor extends ResolvedRaceCompetitor {
  correctedTime?: number;
}

export interface ResultInput {
  finishTime: Date | null;
  laps: number;
  resultCode: ResultCode;
  position?: number | null;
}

/** Per-row editor state for pursuit / level-rating order entry UI */
export interface OrderEntryRowState {
  resultCode: ResultCode;
  /** Optional finish time for Level Rating (competitor info) */
  manualFinishTime?: Date | null;
  /** When set, overrides default sequential rank among finishers */
  rankOverride?: number | null;
}

export interface OrderEntryPersistInput {
  race: Race;
  /** All competitors for this race (from store) */
  competitors: RaceCompetitor[];
  /** Processed queue order (right pane), first = earliest processed */
  processedIds: string[];
  /** State keyed by competitor id for processed rows */
  rowState: Map<string, OrderEntryRowState>;
}

/**
 * Computes target manualPosition for finishers in processed order (ties share the same value).
 * Non-finishers (per isFinishedComp) get no rank (undefined).
 */
export function computeManualPositionsForOrderEntry(
  processedIds: string[],
  rowState: Map<string, OrderEntryRowState>
): Map<string, number | undefined> {
  const out = new Map<string, number | undefined>();
  let nextDefault = 1;
  for (const id of processedIds) {
    const row = rowState.get(id);
    if (!row) {
      out.set(id, undefined);
      continue;
    }
    const code = row.resultCode;
    if (!isFinishedComp(code)) {
      out.set(id, undefined);
      continue;
    }
    const ov = row.rankOverride;
    if (ov != null && !Number.isNaN(Number(ov))) {
      const p = Number(ov);
      out.set(id, p);
      nextDefault = Math.max(nextDefault, p + 1);
    } else {
      out.set(id, nextDefault);
      nextDefault++;
    }
  }
  return out;
}

/** One placing group: boats sharing the same rank (ties). */
export interface TieGroupRow {
  /** Hint from last compute — canonical rank comes from group order after normalize. */
  rank: number;
  ids: string[];
}

/** Split processed queue into placed finishers vs penalties / DNF (order preserved). */
export function segmentProcessedPlacedAndNonPlaced(
  processedIds: string[],
  rowState: Map<string, OrderEntryRowState>
): { placed: string[]; nonPlaced: string[] } {
  const placed: string[] = [];
  const nonPlaced: string[] = [];
  for (const id of processedIds) {
    const row = rowState.get(id);
    const code = row?.resultCode ?? 'NOT FINISHED';
    if (isFinishedComp(code)) {
      placed.push(id);
    } else {
      nonPlaced.push(id);
    }
  }
  return { placed, nonPlaced };
}

export function mergePlacedAndNonPlacedSegments(placed: string[], nonPlaced: string[]): string[] {
  return [...placed, ...nonPlaced];
}

/** Enforce placed segment first, then non-placed. */
export function enforceProcessedSegmentOrder(
  processedIds: string[],
  rowState: Map<string, OrderEntryRowState>
): string[] {
  const { placed, nonPlaced } = segmentProcessedPlacedAndNonPlaced(processedIds, rowState);
  return mergePlacedAndNonPlacedSegments(placed, nonPlaced);
}

/**
 * Consecutive placed finishers with the same effective rank form one tie group.
 */
export function buildTieGroupsFromPlaced(
  placedIds: string[],
  rowState: Map<string, OrderEntryRowState>
): TieGroupRow[] {
  if (placedIds.length === 0) return [];
  const positions = computeManualPositionsForOrderEntry(placedIds, rowState);
  const groups: TieGroupRow[] = [];
  let i = 0;
  while (i < placedIds.length) {
    const id = placedIds[i];
    const row = rowState.get(id);
    if (!row || !isFinishedComp(row.resultCode)) {
      i++;
      continue;
    }
    const p = positions.get(id);
    if (typeof p !== 'number') {
      i++;
      continue;
    }
    const block: string[] = [id];
    let j = i + 1;
    while (j < placedIds.length) {
      const nid = placedIds[j];
      const nrow = rowState.get(nid);
      if (!nrow || !isFinishedComp(nrow.resultCode)) break;
      const np = positions.get(nid);
      if (np !== p) break;
      block.push(nid);
      j++;
    }
    groups.push({ rank: p, ids: block });
    i = j;
  }
  return groups;
}

export function flattenTieGroups(groups: TieGroupRow[]): string[] {
  return groups.flatMap(g => g.ids);
}

/**
 * After reordering tie groups, assign rank 1..n; ties share rankOverride.
 */
export function normalizeRowStateFromOrderedTieGroups(
  orderedGroups: { ids: string[] }[],
  rowState: Map<string, OrderEntryRowState>
): Map<string, OrderEntryRowState> {
  const next = new Map(rowState);
  for (let i = 0; i < orderedGroups.length; i++) {
    const rank = i + 1;
    const ids = orderedGroups[i].ids;
    const shared = ids.length > 1;
    for (const id of ids) {
      const row = next.get(id);
      if (!row) continue;
      next.set(id, { ...row, rankOverride: shared ? rank : null });
    }
  }
  return next;
}

/**
 * Clear tie: clear rankOverride on id, then clear rankOverride on every following row that still has an override.
 */
export function clearTieRankOverrideChain(
  processedIds: string[],
  id: string,
  rowState: Map<string, OrderEntryRowState>
): Map<string, OrderEntryRowState> {
  const idx = processedIds.indexOf(id);
  if (idx < 0) return new Map(rowState);
  const next = new Map(rowState);
  const row = next.get(id);
  if (row) {
    next.set(id, { ...row, rankOverride: null });
  }
  for (let j = idx + 1; j < processedIds.length; j++) {
    const pid = processedIds[j];
    const r = next.get(pid);
    if (r?.rankOverride != null) {
      next.set(pid, { ...r, rankOverride: null });
    }
  }
  return next;
}

export interface CalculatedStats {
  elapsedSeconds: number;
  avgLapTime: number;
}

export type TimeRecordingMode = 'tod' | 'elapsed';

@Injectable({
  providedIn: 'root'
})
export class ManualResultsService {
  private readonly competitorStore = inject(RaceCompetitorStore);
  private readonly raceStore = inject(RaceCalendarStore);
  private readonly seriesEntryStore = inject(SeriesEntryStore);
  private readonly clubStore = inject(ClubStore);

  private statusFromResultCodes(codes: ResultCode[]): RaceStatus | undefined {
    if (codes.length === 0) return undefined;
    const anyStarted = codes.some(code => code !== 'NOT FINISHED');
    if (!anyStarted) return undefined;
    const allCompleted = codes.every(code => code !== 'NOT FINISHED');
    return allCompleted ? 'Completed' : 'In progress';
  }

  /**
   * Calculates derived statistics for a result entry without persisting them.
   * This is useful for providing immediate feedback to the user in the UI.
   * @returns CalculatedStats or null if inputs are invalid.
   */
  calculateStats(finishTime: Date | null, laps: number, startTime: Date | undefined): CalculatedStats | null {
    if (!finishTime || !startTime || laps <= 0) {
      return null;
    }

    const elapsedSeconds = differenceInSeconds(finishTime, startTime);

    if (elapsedSeconds <= 0) {
      return null;
    }

    const avgLapTime = elapsedSeconds / laps;

    return { elapsedSeconds, avgLapTime };
  }

  /** Set start configuration
   * Sets the race start time, updating any results 
   * where the start time has already been set. 
  */
  async setStartTime(raceId: string, starts: RaceStart[], mode: TimeRecordingMode) {
    const primaryStart = starts[0]?.timeOfDay;

    await this.raceStore.updateRace(raceId, {
      actualStart: primaryStart,
      starts,
      timeInputMode: mode
    });

    const race = this.raceStore.allRaces().find(r => r.id === raceId);
    if (!race) return;

    const entries = await this.seriesEntryStore.getSeriesEntries(race.seriesId);
    const entryById = new Map(entries.map(e => [e.id, e] as const));
    const fleetsById = new Map(this.clubStore.club().fleets.map(f => [f.id, f] as const));

    const comps = this.competitorStore.selectedCompetitors().filter(comp => comp.raceId === raceId);

    for (const comp of comps) {
      const entry = entryById.get(comp.seriesEntryId);
      if (!entry) continue;
      const resolvedStart = resolveStartTimeForEntry(entry, starts, fleetsById, primaryStart);
      if (!resolvedStart) continue;
      await this.competitorStore.updateResult(comp.id, { startTime: resolvedStart });
    }

  }

  /**
   * Processes and saves a single competitor's result.
   * It calculates derived values and updates the competitor in the store.
   */
  async recordResult(competitor: RaceCompetitor, race: Race, input: ResultInput): Promise<void> {
    const { finishTime, laps, resultCode, position } = input;

    const update: Partial<RaceCompetitor> = {
      resultCode: resultCode,
    };

    const starts = race.starts;
    const primaryStart = starts?.[0]?.timeOfDay ?? race.actualStart;
    if (primaryStart) {
      const entries = await this.seriesEntryStore.getSeriesEntries(race.seriesId);
      const entry = entries.find(e => e.id === competitor.seriesEntryId);
      const fleetsById = new Map(this.clubStore.club().fleets.map(f => [f.id, f] as const));
      update.startTime = entry
        ? (resolveStartTimeForEntry(entry, starts, fleetsById, primaryStart) ?? primaryStart)
        : primaryStart;
    }

    if (finishTime) {
      update.manualFinishTime = finishTime;
    }

    if (laps) {
      update.manualLaps = laps;
    }

    if (position) {
      update.manualPosition = position;
    }

    // Set a dirty flag on the race to indicate that its results have changed
    // and may need re-scoring. We can build on this later.
    if (!race.dirty) {
      await this.raceStore.updateRace(race.id, { dirty: true });
    }

    await this.competitorStore.updateResult(competitor.id, update);

    const raceCompetitors = this.competitorStore.selectedCompetitors().filter(c => c.raceId === race.id);
    const nextCodes = raceCompetitors.map(c => c.id === competitor.id ? resultCode : c.resultCode);
    const nextStatus = this.statusFromResultCodes(nextCodes);
    if (nextStatus && race.status !== nextStatus) {
      await this.raceStore.updateRace(race.id, { status: nextStatus });
    }
  }

  /**
   * Computes target manualPosition for finishers in processed order.
   * Non-finishers (per isFinishedComp) get no rank (undefined).
   */
  computeManualPositionsForOrderEntry(
    processedIds: string[],
    rowState: Map<string, OrderEntryRowState>
  ): Map<string, number | undefined> {
    return computeManualPositionsForOrderEntry(processedIds, rowState);
  }

  /**
   * Persists order-entry state with diff-only writes (manualPosition, resultCode, manualFinishTime).
   */
  async persistOrderEntryState(input: OrderEntryPersistInput): Promise<void> {
    const { race, competitors, processedIds, rowState } = input;
    const processedSet = new Set(processedIds);
    const positions = computeManualPositionsForOrderEntry(processedIds, rowState);

    const updates: { id: string; patch: Record<string, unknown> }[] = [];

    for (const comp of competitors) {
      const inProcessed = processedSet.has(comp.id);
      const row = rowState.get(comp.id);
      const targetCode: ResultCode = inProcessed && row ? row.resultCode : 'NOT FINISHED';

      const targetManualFinish: Date | undefined | null =
        inProcessed && row ? row.manualFinishTime ?? undefined : undefined;

      const targetMp =
        inProcessed && row && isFinishedComp(targetCode) ? positions.get(comp.id) : undefined;

      const patch: Record<string, unknown> = {};

      if (comp.resultCode !== targetCode) {
        patch['resultCode'] = targetCode;
      }

      const prevTime = comp.manualFinishTime?.getTime();
      const nextTime = targetManualFinish instanceof Date ? targetManualFinish.getTime() : undefined;
      if (prevTime !== nextTime) {
        if (targetManualFinish === undefined || targetManualFinish === null) {
          if (prevTime !== undefined) {
            patch['manualFinishTime'] = deleteField();
          }
        } else {
          patch['manualFinishTime'] = targetManualFinish;
        }
      }

      const prevMp = comp.manualPosition;
      if (targetMp === undefined) {
        if (prevMp !== undefined && prevMp !== null) {
          patch['manualPosition'] = deleteField();
        }
      } else if (prevMp !== targetMp) {
        patch['manualPosition'] = targetMp;
      }

      if (Object.keys(patch).length > 0) {
        updates.push({ id: comp.id, patch });
      }
    }

    const nextCodes: ResultCode[] = competitors.map(comp => {
      const inProcessed = processedSet.has(comp.id);
      const row = rowState.get(comp.id);
      return inProcessed && row ? row.resultCode : 'NOT FINISHED';
    });
    const nextStatus = this.statusFromResultCodes(nextCodes);

    if (updates.length === 0) {
      if (nextStatus && race.status !== nextStatus) {
        await this.raceStore.updateRace(race.id, { status: nextStatus });
      }
      return;
    }

    if (!race.dirty) {
      await this.raceStore.updateRace(race.id, { dirty: true });
    }

    for (const { id, patch } of updates) {
      await this.competitorStore.updateResult(id, patch as Partial<RaceCompetitor>);
    }

    if (nextStatus && race.status !== nextStatus) {
      await this.raceStore.updateRace(race.id, { status: nextStatus });
    }
  }
}

/** Sorts partially completed results
 * Unfinished competitors are placed at the top sorted by class/sail number
 * followed by finished competitors sorted by key value. 
 */
export function manualRaceTableSort(
  a: ResolvedRaceCompetitor,
  b: ResolvedRaceCompetitor,
  finishedOrder: keyof ExtendedRaceCompetitor,
  dir: 'asc' | 'desc' | ''
): number {

  const aAwaitingResult = a.resultCode === 'NOT FINISHED';
  const bAwaitingResult = b.resultCode === 'NOT FINISHED';

  if (aAwaitingResult !== bAwaitingResult) {
    // If one has a result and the other doesnt, one with no result goes first
    return aAwaitingResult ? -1 : 1;
  } else if (aAwaitingResult && bAwaitingResult) {
    // Neither have a result sort by class / boat
    return sortResolvedCompetitors(a, b);
  } else {
    // Both have a result, so sort them accordingly
    return sortCompetitorsWithResult(a, b, finishedOrder, dir);
  }
}

export function sortCompetitorsWithResult(
  a: ExtendedRaceCompetitor,
  b: ExtendedRaceCompetitor,
  finishedOrder: keyof ExtendedRaceCompetitor,
  dir: 'asc' | 'desc' | ''
): number {

  if ((a.resultCode === 'OK') !== (b.resultCode === 'OK')) {
    /* If one is OK and the other not put the OK first  */
    return (a.resultCode === 'OK') ? -1 : 1;
  } else {
    // Both competitors OK - order by specified parameter
    const valueA = a[finishedOrder];
    const valueB = b[finishedOrder];
    let ret = 0;

    if (valueA === undefined || valueA === null || valueB === undefined || valueB === null) {
      if (valueA === valueB) {
        ret = 0;
      } else {
        // If one is missing a value, place the one with a value first
        ret = (valueA === undefined || valueA === null) ? 1 : -1;
      }
    } else if (valueA instanceof Date && valueB instanceof Date) {
      ret = valueA.getTime() - valueB.getTime();
    } else if (typeof valueA === 'number') {
      ret = (valueA as number) - (valueB as number);
    } else if (typeof valueA === 'string') {
      ret = valueA.localeCompare(valueB as string);
    } else {
      console.error('ManualResultsPage: Unexpected sort order: ' + finishedOrder);
      ret = 0;
    }
    return (dir === 'asc') ? ret : -ret;
  }
}

import { PublishedSeriesResult } from '../../published-results';
import { SeriesScoringScheme } from '../model/scoring-algotirhm';
import { PublishedRace, RaceResult } from '../../published-results/model/published-race';
import { getShortAlgorithm, includeInAveragePool, isDiscardable as isResultCodeDiscardable, ResultCodeAlgorithm, isStartAreaComp, isFinishedComp } from '../model/result-code-scoring';
import { SeriesEntry } from '../../results-input';
import { getHandicapValue } from '../model/handicap';
import { HandicapScheme } from '../model/handicap-scheme';
import { mergeKeyFor, type MergeStrategy } from './merge-key';

export interface ScoringConfig {
  seriesType: SeriesScoringScheme;
  discards: number;
  maxOodPerSeries?: number;
  oodAveragePool?: 'finished' | 'started';
}

/**
 * Intermediate data structure for series scoring calculations.
 */
export interface IntermediateSeriesResult extends PublishedSeriesResult {
}

/**
 * Aggregates pre-scored race results into a final, ranked series result.
 *
 * Per-hull RaceResults are grouped by `competitorKey` so that merging
 * strategies (e.g. "score by helm") collapse multiple hulls into a single
 * series row. Display fields (helm, boatClass, sailNumber, handicap, PHB,
 * club, crew) are seeded from the per-hull SeriesEntry corresponding to the
 * *first chronological* race contribution for each merge group; race-level
 * tables continue to show the actual per-race details.
 */
export function scoreSeries(
  races: PublishedRace[],
  seriesEntries: SeriesEntry[],
  config: ScoringConfig,
  handicapScheme: HandicapScheme,
  mergeStrategy: MergeStrategy,
): IntermediateSeriesResult[] {
  const competitorMap = aggregateCompetitorResults(races, seriesEntries, handicapScheme, mergeStrategy);
  const resultsWithTotals = calculateTotalsAndDiscards(Array.from(competitorMap.values()), config);
  const rankedResults = rankCompetitors(resultsWithTotals);

  return rankedResults;
}

/**
 * Builds one IntermediateSeriesResult per distinct merge group. For each
 * group we:
 *
 *   - Iterate races in calendar (`index`) order.
 *   - Pick the first race in which any hull belonging to the group has a
 *     RaceResult; seed display fields from that hull's SeriesEntry.
 *   - For every race after the first appearance: append the group's points
 *     for that race, or a DNC where no hull in the group raced.
 *
 * `dncPoints` for each group is `mergeGroupCount + 1` where mergeGroupCount
 * is the total number of distinct merge groups across the series.
 */
function aggregateCompetitorResults(
  races: PublishedRace[],
  seriesEntries: SeriesEntry[],
  handicapScheme: HandicapScheme,
  mergeStrategy: MergeStrategy,
): Map<string, IntermediateSeriesResult> {
  const entryById = new Map(seriesEntries.map(e => [e.id, e]));

  // Pre-compute merge groups across all known SeriesEntries so DNC counts and
  // ranking domain are consistent even for hulls that haven't raced yet.
  const groupMembers = new Map<string, SeriesEntry[]>();
  for (const entry of seriesEntries) {
    const key = mergeKeyFor(entry, mergeStrategy);
    const list = groupMembers.get(key);
    if (list) {
      list.push(entry);
    } else {
      groupMembers.set(key, [entry]);
    }
  }

  const dncPoints = groupMembers.size + 1;

  // Sort races chronologically by calendar index for "first appearance" lookups.
  const orderedRaces = [...races].sort((a, b) => a.index - b.index);

  const competitorMap = new Map<string, IntermediateSeriesResult>();

  // Initialise every known merge group, even if they haven't yet raced.
  for (const [key, members] of groupMembers) {
    // Default seed: lowest-id member. Will be overridden when the group's
    // first actual race contribution is found below.
    const seed = members[0];
    competitorMap.set(key, makeSeriesRow(key, seed, handicapScheme));
  }

  // Walk races in chronological order to seed display from first appearance
  // and to append per-race scores.
  const seededKeys = new Set<string>();

  for (const race of orderedRaces) {
    // Group the per-hull race results by competitorKey for this race. If two
    // hulls in the same merge group somehow appear in the same race we keep
    // the best (lowest) score and remember the first contribution for display.
    const racePointsByKey = new Map<string, { points: number; resultCode: RaceResult['resultCode']; firstResult: RaceResult }>();
    for (const r of race.results) {
      const existing = racePointsByKey.get(r.competitorKey);
      if (!existing) {
        racePointsByKey.set(r.competitorKey, { points: r.points, resultCode: r.resultCode, firstResult: r });
      } else if (r.points < existing.points) {
        racePointsByKey.set(r.competitorKey, { points: r.points, resultCode: r.resultCode, firstResult: existing.firstResult });
      }
    }

    for (const [key, row] of competitorMap) {
      const contribution = racePointsByKey.get(key);

      if (contribution && !seededKeys.has(key)) {
        // First time this merge group races: seed display fields from the
        // SeriesEntry of this race's contribution.
        const entry = entryById.get(contribution.firstResult.seriesEntryId);
        if (entry) {
          seedDisplayFromEntry(row, entry, handicapScheme);
        }
        seededKeys.add(key);
      }

      if (contribution) {
        row.raceScores.push({
          raceIndex: race.index,
          points: contribution.points,
          resultCode: contribution.resultCode,
          isDiscard: false,
        });
      } else {
        row.raceScores.push({
          raceIndex: race.index,
          points: dncPoints,
          resultCode: 'DNC',
          isDiscard: false,
        });
      }
    }
  }

  return competitorMap;
}

function makeSeriesRow(
  competitorKey: string,
  seed: SeriesEntry,
  handicapScheme: HandicapScheme,
): IntermediateSeriesResult {
  return {
    competitorKey,
    seriesEntryId: seed.id,
    helm: seed.helm,
    crew: seed.crew,
    sailNumber: seed.sailNumber,
    club: seed.club || '',
    handicap: getHandicapValue(seed.handicaps, handicapScheme) ?? 0,
    personalHandicapBand: seed.personalHandicapBand,
    handicapScheme,
    boatClass: seed.boatClass,
    raceScores: [],
    totalPoints: 0,
    netPoints: 0,
    rank: 0,
    scoresForTiebreak: [],
  };
}

function seedDisplayFromEntry(
  row: IntermediateSeriesResult,
  entry: SeriesEntry,
  handicapScheme: HandicapScheme,
): void {
  row.seriesEntryId = entry.id;
  row.helm = entry.helm;
  row.crew = entry.crew;
  row.sailNumber = entry.sailNumber;
  row.club = entry.club || '';
  row.handicap = getHandicapValue(entry.handicaps, handicapScheme) ?? 0;
  row.personalHandicapBand = entry.personalHandicapBand;
  row.boatClass = entry.boatClass;
}

function calculateTotalsAndDiscards(
  results: IntermediateSeriesResult[], 
  config: ScoringConfig): IntermediateSeriesResult[] {

  const dncPoints = results.length + 1;

  // Calculate total and net points after all races are processed
  for (const result of results) {

    // Apply average scores directly. This must be done before discards are calculated.
    applyIsafRedress(result, dncPoints);
    applyClubOod(result, dncPoints, config);

    // Identify discardable scores and sort them descending to find the worst ones.
    const scoresToDiscard = result.raceScores
      .filter(s => isResultCodeDiscardable(s.resultCode)) // Creates copy so original raceScore is not mutated
      .sort((a, b) => b.points - a.points)
      .slice(0, config.discards);

    // Set the isDiscard flag on the original raceScore objects
    scoresToDiscard.forEach(s => s.isDiscard = true);

    const scoresToCount = result.raceScores.filter(s => !s.isDiscard);

    result.netPoints = scoresToCount.reduce((acc, r) => acc + r.points, 0);
    result.totalPoints = result.raceScores.reduce((acc, r) => acc + r.points, 0);
  }
  return results;
}

/** Sets the points for ISAF Redress codes (RDGA, RDGB) */
function applyIsafRedress(result: IntermediateSeriesResult, dncPoints: number) {
  // ISAF Pool: All races except average codes (RDGA, RDGB, OOD)
  const isafPool = result.raceScores.filter(s => includeInAveragePool(s.resultCode));

  const isafAvgTotal = isafPool.reduce((acc, s) => acc + s.points, 0);
  const isafAvgAll = isafPool.length > 0 ? Math.round((isafAvgTotal / isafPool.length) * 10) / 10 : dncPoints;

  for (const score of result.raceScores) {
    const algorithm = getShortAlgorithm(score.resultCode);

    if (algorithm === ResultCodeAlgorithm.isafAvgAll) {
      score.points = isafAvgAll;
    } else if (algorithm === ResultCodeAlgorithm.isafAvgBefore) {
      const scoresBefore = isafPool.filter(s => s.raceIndex < score.raceIndex);
      if (scoresBefore.length > 0) {
        const totalBefore = scoresBefore.reduce((acc, s) => acc + s.points, 0);
        score.points = Math.round((totalBefore / scoresBefore.length) * 10) / 10;
      } else {
        score.points = dncPoints;
      }
    }
  }
}

/** Sets the points for Club OOD duties */
function applyClubOod(result: IntermediateSeriesResult, dncPoints: number, config: ScoringConfig) {
  const maxOod = config.maxOodPerSeries ?? 999;
  const oodPoolType = config.oodAveragePool ?? 'finished';

  // Base pool: All races except average codes
  const basePool = result.raceScores.filter(s => includeInAveragePool(s.resultCode));

  // OOD Pool: 'finished' (FINISHED_AND_SCORED) or 'started' (isStartAreaComp)
  const oodPool = basePool.filter(s => {
    if (oodPoolType === 'finished') return isFinishedComp(s.resultCode) && s.resultCode !== 'DNC';
    if (oodPoolType === 'started') return isStartAreaComp(s.resultCode);
    return false;
  });

  const oodAvgTotal = oodPool.reduce((acc, s) => acc + s.points, 0);
  const oodAvg = oodPool.length > 0 ? Math.round((oodAvgTotal / oodPool.length) * 10) / 10 : dncPoints;

  let oodCount = 0;

  // Process chronologically to correctly apply maxOodPerSeries cap
  const chronologicalScores = [...result.raceScores].sort((a, b) => a.raceIndex - b.raceIndex);

  for (const score of chronologicalScores) {
    const algorithm = getShortAlgorithm(score.resultCode);

    if (algorithm === ResultCodeAlgorithm.clubOodAverage) {
      if (oodCount < maxOod) {
        score.points = oodAvg;
        oodCount++;
      } else {
        score.points = dncPoints; // Cap reached
      }
    }
  }
}

function rankCompetitors(results: IntermediateSeriesResult[]): IntermediateSeriesResult[] {
  // For tie-breaking (A8.1), create a sorted list of scores for each competitor
  results.forEach(result => {
    result.scoresForTiebreak = result.raceScores.filter(r => !r.isDiscard).map(r => r.points).sort((a, b) => a - b);
  });

  results.sort((a, b) => {
    // Primary sort by net points (ascending)
    if (a.netPoints !== b.netPoints) {
      return a.netPoints - b.netPoints;
    }

    // Tie-break A8.1: most firsts, seconds, etc.
    for (let i = 0; i < Math.min(a.scoresForTiebreak.length, b.scoresForTiebreak.length); i++) {
      if (a.scoresForTiebreak[i] !== b.scoresForTiebreak[i]) {
        return a.scoresForTiebreak[i] - b.scoresForTiebreak[i];
      }
    }

    // Tie-break A8.2: score in the last race
    if (a.raceScores.length > 0 && b.raceScores.length > 0) {
      // Find the score from the most recent race (highest raceIndex)
      const lastRaceA = a.raceScores.reduce((prev, current) => (prev.raceIndex > current.raceIndex) ? prev : current);
      const lastRaceB = b.raceScores.find(s => s.raceIndex === lastRaceA.raceIndex)!;
      return lastRaceA.points - lastRaceB.points;
    }

    return 0;
  });

  // Assign ranks
  let currentRank = 1;
  for (let i = 0; i < results.length; i++) {
    if (i > 0 && isTied(results[i - 1], results[i])) {
      results[i].rank = results[i - 1].rank;
    } else {
      results[i].rank = currentRank;
    }
    currentRank++;
  }

  return results;
}

function isTied(a: IntermediateSeriesResult, b: IntermediateSeriesResult): boolean {
  if (a.netPoints !== b.netPoints) {
    return false;
  }

  if (a.scoresForTiebreak.length !== b.scoresForTiebreak.length) {
    return false;
  }

  for (let i = 0; i < a.scoresForTiebreak.length; i++) {
    if (a.scoresForTiebreak[i] !== b.scoresForTiebreak[i]) {
      return false;
    }
  }

  return true;
}

export interface Season {
   id: string;
   name: string;
}

import { ScoringConfiguration } from "app/scoring/model/scoring-configuration";
import { SeriesScoringScheme } from "app/scoring/model/scoring-algotirhm";
import { SeriesEntryMatchingStrategy } from "app/entry/model/entry-grouping";

export interface Series {
   id: string;
   seasonId: string;
   name: string;
   startDate?: Date | null;
   endDate?: Date | null;
   archived: boolean;

   // Base scoring rules
   scoringAlgorithm: SeriesScoringScheme;
   /**
    * Controls how per-hull SeriesEntries are *merged* during series-level
    * scoring (see `mergeKeyFor`). Per-hull entries are always created at
    * sign-on regardless of this setting.
    */
   entryAlgorithm: SeriesEntryMatchingStrategy;
   initialDiscardAfter: number;
   subsequentDiscardsEveryN: number;

   // Scoring configurations
   primaryScoringConfiguration: ScoringConfiguration;
   secondaryScoringConfigurations?: ScoringConfiguration[];
   dirty?: boolean;
}

import { Handicap } from 'app/scoring/model/handicap';
import { PersonalHandicapBand } from 'app/scoring/model/personal-handicap';

export interface SeriesEntry {
   id: string;
   seriesId: string;

   // Core Identity
   helm: string;
   crew?: string;
   club?: string;

   // Default Boat Details
   boatClass: string;
   sailNumber: number;
   handicaps: Handicap[];
   personalHandicapBand?: PersonalHandicapBand;
   fleetId?: string;

   // For subset scoring
   tags?: string[];
}

export interface SeriesInfo {
   id: string;
   baseSeriesId?: string;
   name: string;
   fleetId: string;
   startDate: Date;
   endDate: Date;
   raceCount: number;
   /** Rolling count of races in the last 6 days for this published series. */
   recentRaceCount6d?: number;
   /** Scheduled start of the last published race in this series. */
   lastPublishedRaceStart?: Date;
}

export interface PublishedSeason {
   id: string;
   name: string;
   series: SeriesInfo[];
}

import { HandicapScheme } from 'app/scoring/model/handicap-scheme';

export interface GeneralHandicapFleet {
   type: 'GeneralHandicap';
   id: string;
   name: 'General Handicap';
}

export interface BoatClassFleet {
   type: 'BoatClass';
   id: string;
   boatClassId: string;
}

export interface HandicapRangeFleet {
   type: 'HandicapRange';
   id: string;
   name: string;
   scheme: HandicapScheme;
   min: number;
   max: number;
}

export interface TagFleet {
   type: 'Tag';
   id: string;
   name: string; // e.g. "Novice"
   value: string; // The tag string to match, e.g. "Novice"
}

export type Fleet = GeneralHandicapFleet | BoatClassFleet | HandicapRangeFleet | TagFleet;

export function getFleetName(fleet: Fleet): string {
   switch (fleet.type) {
      case 'GeneralHandicap':
         return 'General Handicap';
      case 'BoatClass':
         return fleet.boatClassId;
      case 'HandicapRange':
         return fleet.name;
      case 'Tag':
         return fleet.name;
   }
}

import { Injectable, inject } from '@angular/core';
import { Race, RaceCalendarStore } from 'app/race-calender';
import { ClubStore } from 'app/club-tenant';
import type { RaceStatus } from 'app/race-calender/model/race-status';
import { ResultCode } from 'app/scoring/model/result-code';
import { isFinishedComp } from 'app/scoring/model/result-code-scoring';
import { differenceInSeconds } from 'date-fns';
import { deleteField } from 'firebase/firestore';
import { RaceCompetitorStore } from './race-competitor-store';
import { RaceCompetitor } from '../model/race-competitor';
import { ResolvedRaceCompetitor, sortResolvedCompetitors } from '../model/resolved-race-competitor';
import { SeriesEntryStore } from './series-entry-store';
import { resolveStartTimeForEntry } from './race-start-resolver';
import type { RaceStart } from 'app/race-calender/model/race-start';

/**
 * View model used by the manual results table. Adds a derived `correctedTime`
 * to a `ResolvedRaceCompetitor`. Sorting and identity continue to come from
 * the underlying SeriesEntry.
 */
export class ExtendedRaceCompetitor extends ResolvedRaceCompetitor {
  correctedTime?: number;
}

export interface ResultInput {
  finishTime: Date | null;
  laps: number;
  resultCode: ResultCode;
  position?: number | null;
}

/** Per-row editor state for pursuit / level-rating order entry UI */
export interface OrderEntryRowState {
  resultCode: ResultCode;
  /** Optional finish time for Level Rating (competitor info) */
  manualFinishTime?: Date | null;
  /** When set, overrides default sequential rank among finishers */
  rankOverride?: number | null;
}

export interface OrderEntryPersistInput {
  race: Race;
  /** All competitors for this race (from store) */
  competitors: RaceCompetitor[];
  /** Processed queue order (right pane), first = earliest processed */
  processedIds: string[];
  /** State keyed by competitor id for processed rows */
  rowState: Map<string, OrderEntryRowState>;
}

/**
 * Computes target manualPosition for finishers in processed order (ties share the same value).
 * Non-finishers (per isFinishedComp) get no rank (undefined).
 */
export function computeManualPositionsForOrderEntry(
  processedIds: string[],
  rowState: Map<string, OrderEntryRowState>
): Map<string, number | undefined> {
  const out = new Map<string, number | undefined>();
  let nextDefault = 1;
  for (const id of processedIds) {
    const row = rowState.get(id);
    if (!row) {
      out.set(id, undefined);
      continue;
    }
    const code = row.resultCode;
    if (!isFinishedComp(code)) {
      out.set(id, undefined);
      continue;
    }
    const ov = row.rankOverride;
    if (ov != null && !Number.isNaN(Number(ov))) {
      const p = Number(ov);
      out.set(id, p);
      nextDefault = Math.max(nextDefault, p + 1);
    } else {
      out.set(id, nextDefault);
      nextDefault++;
    }
  }
  return out;
}

/** One placing group: boats sharing the same rank (ties). */
export interface TieGroupRow {
  /** Hint from last compute — canonical rank comes from group order after normalize. */
  rank: number;
  ids: string[];
}

/** Split processed queue into placed finishers vs penalties / DNF (order preserved). */
export function segmentProcessedPlacedAndNonPlaced(
  processedIds: string[],
  rowState: Map<string, OrderEntryRowState>
): { placed: string[]; nonPlaced: string[] } {
  const placed: string[] = [];
  const nonPlaced: string[] = [];
  for (const id of processedIds) {
    const row = rowState.get(id);
    const code = row?.resultCode ?? 'NOT FINISHED';
    if (isFinishedComp(code)) {
      placed.push(id);
    } else {
      nonPlaced.push(id);
    }
  }
  return { placed, nonPlaced };
}

export function mergePlacedAndNonPlacedSegments(placed: string[], nonPlaced: string[]): string[] {
  return [...placed, ...nonPlaced];
}

/** Enforce placed segment first, then non-placed. */
export function enforceProcessedSegmentOrder(
  processedIds: string[],
  rowState: Map<string, OrderEntryRowState>
): string[] {
  const { placed, nonPlaced } = segmentProcessedPlacedAndNonPlaced(processedIds, rowState);
  return mergePlacedAndNonPlacedSegments(placed, nonPlaced);
}

/**
 * Consecutive placed finishers with the same effective rank form one tie group.
 */
export function buildTieGroupsFromPlaced(
  placedIds: string[],
  rowState: Map<string, OrderEntryRowState>
): TieGroupRow[] {
  if (placedIds.length === 0) return [];
  const positions = computeManualPositionsForOrderEntry(placedIds, rowState);
  const groups: TieGroupRow[] = [];
  let i = 0;
  while (i < placedIds.length) {
    const id = placedIds[i];
    const row = rowState.get(id);
    if (!row || !isFinishedComp(row.resultCode)) {
      i++;
      continue;
    }
    const p = positions.get(id);
    if (typeof p !== 'number') {
      i++;
      continue;
    }
    const block: string[] = [id];
    let j = i + 1;
    while (j < placedIds.length) {
      const nid = placedIds[j];
      const nrow = rowState.get(nid);
      if (!nrow || !isFinishedComp(nrow.resultCode)) break;
      const np = positions.get(nid);
      if (np !== p) break;
      block.push(nid);
      j++;
    }
    groups.push({ rank: p, ids: block });
    i = j;
  }
  return groups;
}

export function flattenTieGroups(groups: TieGroupRow[]): string[] {
  return groups.flatMap(g => g.ids);
}

/**
 * After reordering tie groups, assign rank 1..n; ties share rankOverride.
 */
export function normalizeRowStateFromOrderedTieGroups(
  orderedGroups: { ids: string[] }[],
  rowState: Map<string, OrderEntryRowState>
): Map<string, OrderEntryRowState> {
  const next = new Map(rowState);
  for (let i = 0; i < orderedGroups.length; i++) {
    const rank = i + 1;
    const ids = orderedGroups[i].ids;
    const shared = ids.length > 1;
    for (const id of ids) {
      const row = next.get(id);
      if (!row) continue;
      next.set(id, { ...row, rankOverride: shared ? rank : null });
    }
  }
  return next;
}

/**
 * Clear tie: clear rankOverride on id, then clear rankOverride on every following row that still has an override.
 */
export function clearTieRankOverrideChain(
  processedIds: string[],
  id: string,
  rowState: Map<string, OrderEntryRowState>
): Map<string, OrderEntryRowState> {
  const idx = processedIds.indexOf(id);
  if (idx < 0) return new Map(rowState);
  const next = new Map(rowState);
  const row = next.get(id);
  if (row) {
    next.set(id, { ...row, rankOverride: null });
  }
  for (let j = idx + 1; j < processedIds.length; j++) {
    const pid = processedIds[j];
    const r = next.get(pid);
    if (r?.rankOverride != null) {
      next.set(pid, { ...r, rankOverride: null });
    }
  }
  return next;
}

export interface CalculatedStats {
  elapsedSeconds: number;
  avgLapTime: number;
}

export type TimeRecordingMode = 'tod' | 'elapsed';

@Injectable({
  providedIn: 'root'
})
export class ManualResultsService {
  private readonly competitorStore = inject(RaceCompetitorStore);
  private readonly raceStore = inject(RaceCalendarStore);
  private readonly seriesEntryStore = inject(SeriesEntryStore);
  private readonly clubStore = inject(ClubStore);

  private statusFromResultCodes(codes: ResultCode[]): RaceStatus | undefined {
    if (codes.length === 0) return undefined;
    const anyStarted = codes.some(code => code !== 'NOT FINISHED');
    if (!anyStarted) return undefined;
    const allCompleted = codes.every(code => code !== 'NOT FINISHED');
    return allCompleted ? 'Completed' : 'In progress';
  }

  /**
   * Calculates derived statistics for a result entry without persisting them.
   * This is useful for providing immediate feedback to the user in the UI.
   * @returns CalculatedStats or null if inputs are invalid.
   */
  calculateStats(finishTime: Date | null, laps: number, startTime: Date | undefined): CalculatedStats | null {
    if (!finishTime || !startTime || laps <= 0) {
      return null;
    }

    const elapsedSeconds = differenceInSeconds(finishTime, startTime);

    if (elapsedSeconds <= 0) {
      return null;
    }

    const avgLapTime = elapsedSeconds / laps;

    return { elapsedSeconds, avgLapTime };
  }

  /** Set start configuration
   * Sets the race start time, updating any results 
   * where the start time has already been set. 
  */
  async setStartTime(raceId: string, starts: RaceStart[], mode: TimeRecordingMode) {
    const primaryStart = starts[0]?.timeOfDay;

    await this.raceStore.updateRace(raceId, {
      actualStart: primaryStart,
      starts,
      timeInputMode: mode
    });

    const race = this.raceStore.allRaces().find(r => r.id === raceId);
    if (!race) return;

    const entries = await this.seriesEntryStore.getSeriesEntries(race.seriesId);
    const entryById = new Map(entries.map(e => [e.id, e] as const));
    const fleetsById = new Map(this.clubStore.club().fleets.map(f => [f.id, f] as const));

    const comps = this.competitorStore.selectedCompetitors().filter(comp => comp.raceId === raceId);

    for (const comp of comps) {
      const entry = entryById.get(comp.seriesEntryId);
      if (!entry) continue;
      const resolvedStart = resolveStartTimeForEntry(entry, starts, fleetsById, primaryStart);
      if (!resolvedStart) continue;
      await this.competitorStore.updateResult(comp.id, { startTime: resolvedStart });
    }

  }

  /**
   * Processes and saves a single competitor's result.
   * It calculates derived values and updates the competitor in the store.
   */
  async recordResult(competitor: RaceCompetitor, race: Race, input: ResultInput): Promise<void> {
    const { finishTime, laps, resultCode, position } = input;

    const update: Partial<RaceCompetitor> = {
      resultCode: resultCode,
    };

    const starts = race.starts;
    const primaryStart = starts?.[0]?.timeOfDay ?? race.actualStart;
    if (primaryStart) {
      const entries = await this.seriesEntryStore.getSeriesEntries(race.seriesId);
      const entry = entries.find(e => e.id === competitor.seriesEntryId);
      const fleetsById = new Map(this.clubStore.club().fleets.map(f => [f.id, f] as const));
      update.startTime = entry
        ? (resolveStartTimeForEntry(entry, starts, fleetsById, primaryStart) ?? primaryStart)
        : primaryStart;
    }

    if (finishTime) {
      update.manualFinishTime = finishTime;
    }

    if (laps) {
      update.manualLaps = laps;
    }

    if (position) {
      update.manualPosition = position;
    }

    // Set a dirty flag on the race to indicate that its results have changed
    // and may need re-scoring. We can build on this later.
    if (!race.dirty) {
      await this.raceStore.updateRace(race.id, { dirty: true });
    }

    await this.competitorStore.updateResult(competitor.id, update);

    const raceCompetitors = this.competitorStore.selectedCompetitors().filter(c => c.raceId === race.id);
    const nextCodes = raceCompetitors.map(c => c.id === competitor.id ? resultCode : c.resultCode);
    const nextStatus = this.statusFromResultCodes(nextCodes);
    if (nextStatus && race.status !== nextStatus) {
      await this.raceStore.updateRace(race.id, { status: nextStatus });
    }
  }

  /**
   * Computes target manualPosition for finishers in processed order.
   * Non-finishers (per isFinishedComp) get no rank (undefined).
   */
  computeManualPositionsForOrderEntry(
    processedIds: string[],
    rowState: Map<string, OrderEntryRowState>
  ): Map<string, number | undefined> {
    return computeManualPositionsForOrderEntry(processedIds, rowState);
  }

  /**
   * Persists order-entry state with diff-only writes (manualPosition, resultCode, manualFinishTime).
   */
  async persistOrderEntryState(input: OrderEntryPersistInput): Promise<void> {
    const { race, competitors, processedIds, rowState } = input;
    const processedSet = new Set(processedIds);
    const positions = computeManualPositionsForOrderEntry(processedIds, rowState);

    const updates: { id: string; patch: Record<string, unknown> }[] = [];

    for (const comp of competitors) {
      const inProcessed = processedSet.has(comp.id);
      const row = rowState.get(comp.id);
      const targetCode: ResultCode = inProcessed && row ? row.resultCode : 'NOT FINISHED';

      const targetManualFinish: Date | undefined | null =
        inProcessed && row ? row.manualFinishTime ?? undefined : undefined;

      const targetMp =
        inProcessed && row && isFinishedComp(targetCode) ? positions.get(comp.id) : undefined;

      const patch: Record<string, unknown> = {};

      if (comp.resultCode !== targetCode) {
        patch['resultCode'] = targetCode;
      }

      const prevTime = comp.manualFinishTime?.getTime();
      const nextTime = targetManualFinish instanceof Date ? targetManualFinish.getTime() : undefined;
      if (prevTime !== nextTime) {
        if (targetManualFinish === undefined || targetManualFinish === null) {
          if (prevTime !== undefined) {
            patch['manualFinishTime'] = deleteField();
          }
        } else {
          patch['manualFinishTime'] = targetManualFinish;
        }
      }

      const prevMp = comp.manualPosition;
      if (targetMp === undefined) {
        if (prevMp !== undefined && prevMp !== null) {
          patch['manualPosition'] = deleteField();
        }
      } else if (prevMp !== targetMp) {
        patch['manualPosition'] = targetMp;
      }

      if (Object.keys(patch).length > 0) {
        updates.push({ id: comp.id, patch });
      }
    }

    const nextCodes: ResultCode[] = competitors.map(comp => {
      const inProcessed = processedSet.has(comp.id);
      const row = rowState.get(comp.id);
      return inProcessed && row ? row.resultCode : 'NOT FINISHED';
    });
    const nextStatus = this.statusFromResultCodes(nextCodes);

    if (updates.length === 0) {
      if (nextStatus && race.status !== nextStatus) {
        await this.raceStore.updateRace(race.id, { status: nextStatus });
      }
      return;
    }

    if (!race.dirty) {
      await this.raceStore.updateRace(race.id, { dirty: true });
    }

    for (const { id, patch } of updates) {
      await this.competitorStore.updateResult(id, patch as Partial<RaceCompetitor>);
    }

    if (nextStatus && race.status !== nextStatus) {
      await this.raceStore.updateRace(race.id, { status: nextStatus });
    }
  }
}

/** Sorts partially completed results
 * Unfinished competitors are placed at the top sorted by class/sail number
 * followed by finished competitors sorted by key value. 
 */
export function manualRaceTableSort(
  a: ResolvedRaceCompetitor,
  b: ResolvedRaceCompetitor,
  finishedOrder: keyof ExtendedRaceCompetitor,
  dir: 'asc' | 'desc' | ''
): number {

  const aAwaitingResult = a.resultCode === 'NOT FINISHED';
  const bAwaitingResult = b.resultCode === 'NOT FINISHED';

  if (aAwaitingResult !== bAwaitingResult) {
    // If one has a result and the other doesnt, one with no result goes first
    return aAwaitingResult ? -1 : 1;
  } else if (aAwaitingResult && bAwaitingResult) {
    // Neither have a result sort by class / boat
    return sortResolvedCompetitors(a, b);
  } else {
    // Both have a result, so sort them accordingly
    return sortCompetitorsWithResult(a, b, finishedOrder, dir);
  }
}

export function sortCompetitorsWithResult(
  a: ExtendedRaceCompetitor,
  b: ExtendedRaceCompetitor,
  finishedOrder: keyof ExtendedRaceCompetitor,
  dir: 'asc' | 'desc' | ''
): number {

  if ((a.resultCode === 'OK') !== (b.resultCode === 'OK')) {
    /* If one is OK and the other not put the OK first  */
    return (a.resultCode === 'OK') ? -1 : 1;
  } else {
    // Both competitors OK - order by specified parameter
    const valueA = a[finishedOrder];
    const valueB = b[finishedOrder];
    let ret = 0;

    if (valueA === undefined || valueA === null || valueB === undefined || valueB === null) {
      if (valueA === valueB) {
        ret = 0;
      } else {
        // If one is missing a value, place the one with a value first
        ret = (valueA === undefined || valueA === null) ? 1 : -1;
      }
    } else if (valueA instanceof Date && valueB instanceof Date) {
      ret = valueA.getTime() - valueB.getTime();
    } else if (typeof valueA === 'number') {
      ret = (valueA as number) - (valueB as number);
    } else if (typeof valueA === 'string') {
      ret = valueA.localeCompare(valueB as string);
    } else {
      console.error('ManualResultsPage: Unexpected sort order: ' + finishedOrder);
      ret = 0;
    }
    return (dir === 'asc') ? ret : -ret;
  }
}

import { computed, inject, Injectable, Injector, signal } from '@angular/core';
import { toObservable, toSignal } from '@angular/core/rxjs-interop';
import { collectionData, docData, orderBy, query } from '@angular/fire/firestore';
import type { Observable } from 'rxjs';
import { catchError, combineLatest, map, of, switchMap, tap, timer } from 'rxjs';

import { FirestoreTenantService } from 'app/club-tenant/services/firestore-tenant';
import type { HandicapScheme } from 'app/scoring/model/handicap-scheme';

import type { PublishedRace } from '../model/published-race';
import type { SeriesInfo } from '../model/published-season';
import type { PublishedSeries } from '../model/published-series';
import { PUBLISHED_SERIES_PATH, PublishedResultsReader } from './published-results-store';
import {
  isScheduledInRecentLocalDays,
  isScheduledToday,
  uniqueSeriesCandidatesForDay,
  uniqueSeriesCandidatesForRecentDays,
} from './todays-published-races.utils';

export type PublishedRacesMode = 'today' | 'recent6d';

export interface TodaysPublishedRaceBlock {
  seriesId: string;
  seriesName: string;
  fleetId: string;
  scoringHandicapScheme: HandicapScheme | undefined;
  race: PublishedRace;
}

/**
 * Live Firestore view of today's published races for the current club.
 *
 * Provided on the Today's results route component only so subscriptions are torn down
 * when leaving the route (no long-lived listeners on a singleton).
 */
@Injectable()
export class TodaysPublishedRacesService {
  private static readonly EMPTY_BLOCKS: TodaysPublishedRaceBlock[] = [];
  private static readonly RECENT_DAYS = 6;

  private readonly injector = inject(Injector);
  private readonly tenant = inject(FirestoreTenantService);
  private readonly reader = inject(PublishedResultsReader);

  private readonly blocksErrorSignal = signal<unknown>(undefined);
  readonly mode = signal<PublishedRacesMode>('recent6d');

  /**
   * Seasons index + a one-minute tick so we re-evaluate "today" around midnight
   * and when the calendar-day filter should change without a manual refresh.
   */
  private readonly blocks$ = combineLatest([
    toObservable(this.reader.seasons, { injector: this.injector }),
    timer(0, 60_000),
    toObservable(this.mode, { injector: this.injector }),
  ]).pipe(
    tap(() => this.blocksErrorSignal.set(undefined)),
    switchMap(([seasons, _tick, mode]) => {
      const now = new Date();
      const candidates =
        mode === 'today'
          ? uniqueSeriesCandidatesForDay(seasons, now)
          : uniqueSeriesCandidatesForRecentDays(seasons, TodaysPublishedRacesService.RECENT_DAYS, now);
      if (candidates.length === 0) {
        return of(TodaysPublishedRacesService.EMPTY_BLOCKS);
      }
      return combineLatest(candidates.map(c => this.watchSeriesBlocks(c, mode))).pipe(
        map(parts => this.flattenAndSort(parts)),
      );
    }),
    catchError(err => {
      console.error('TodaysPublishedRacesService: stream failed', err);
      this.blocksErrorSignal.set(err);
      return of(TodaysPublishedRacesService.EMPTY_BLOCKS);
    }),
  );

  readonly blocks = toSignal(this.blocks$, {
    injector: this.injector,
    initialValue: TodaysPublishedRacesService.EMPTY_BLOCKS,
  });

  readonly loadError = computed(() => this.blocksErrorSignal());

  /** True until the published seasons index has first loaded from Firestore. */
  readonly loading = computed(() => this.reader.seasonsLoading());

  private watchSeriesBlocks(info: SeriesInfo, mode: PublishedRacesMode): Observable<TodaysPublishedRaceBlock[]> {
    const seriesId = info.id;
    const seriesRef = this.tenant.docRef<PublishedSeries>(PUBLISHED_SERIES_PATH, seriesId);
    const racesQuery = query(
      this.tenant.collectionRef<PublishedRace>(PUBLISHED_SERIES_PATH, seriesId, 'races'),
      orderBy('scheduledStart', 'asc'),
    );
    return combineLatest({
      series: docData(seriesRef),
      races: collectionData(racesQuery),
    }).pipe(
      map(({ series, races }) => {
        if (!series) return [];
        const scheme = series.competitors[0]?.handicapScheme;
        const day = new Date();
        const out: TodaysPublishedRaceBlock[] = [];
        for (const race of races) {
          const includeRace =
            mode === 'today'
              ? isScheduledToday(race.scheduledStart, day)
              : isScheduledInRecentLocalDays(
                  race.scheduledStart,
                  TodaysPublishedRacesService.RECENT_DAYS,
                  day,
                );
          if (includeRace) {
            out.push({
              seriesId,
              seriesName: series.name,
              fleetId: series.fleetId,
              scoringHandicapScheme: scheme,
              race,
            });
          }
        }
        return out;
      }),
      catchError(err => {
        console.warn(`TodaysPublishedRacesService: series ${seriesId}`, err);
        return of([]);
      }),
    );
  }

  private flattenAndSort(parts: TodaysPublishedRaceBlock[][]): TodaysPublishedRaceBlock[] {
    const flat = parts.flat();
    flat.sort(
      (a, b) =>
        b.race.scheduledStart.getTime() - a.race.scheduledStart.getTime() ||
        a.seriesName.localeCompare(b.seriesName) ||
        b.race.index - a.race.index,
    );
    return flat;
  }
}

