import { computed, Injectable, Signal } from '@angular/core';
import { rxResource } from '@angular/core/rxjs-interop';
import { Series } from '../model/series';
import { Race } from '../model/race';
import { collectionData, query, where, writeBatch, doc, getDoc, getDocs } from '@angular/fire/firestore';
import { Observable, map, tap } from 'rxjs';
import { isSameDay } from 'date-fns';
import { RaceCalendarStoreBase, RaceSeriesDetails, seriesSort, sortRaces } from './race-calendar-store-base';
import { generateSecureID } from 'app/shared/firebase/firestore-helper';

/** Service that returns the complete race calander 
 * Used for race calander administration and planning
 */
@Injectable({
   providedIn: 'root',
})
export class RaceCalendarStore extends RaceCalendarStoreBase {

   // Fetch only active series (not archived)
   private readonly seriesResource = rxResource<Series[], unknown>({
      stream: (): Observable<Series[]> =>
         collectionData(
            query(this.seriesCollection, where('archived', '==', false)),
            { idField: 'id' }
         ).pipe(
            map(seriesList => [...seriesList].sort(seriesSort)),
            tap(seriesList => console.log(`FullRaceCalander. Loaded ${seriesList.length} series`))
         ),
      defaultValue: [],
   });

   private readonly racesResource = rxResource<Race[], unknown>({
      stream: (): Observable<Race[]> =>
         collectionData(
            query(this.racesCollection, where('status', '!=', 'Archived')),
            { idField: 'id' }
         ).pipe(
            map(races => races.sort(sortRaces)),
            tap(races => console.log(`FullRaceCalander. Loaded ${races.length} races`))
         ),
      defaultValue: []
   });

   readonly allSeries = this.seriesResource.value.asReadonly();
   readonly isLoading = this.seriesResource.isLoading;
   readonly error = this.seriesResource.error;

   readonly allRaces = this.racesResource.value.asReadonly();
   readonly racesLoading = this.racesResource.isLoading;
   readonly racesError = this.racesResource.error;

   getSeries(id: Signal<string>): Signal<Series | undefined> {
      return computed(() => this.allSeries().find(s => s.id === id()));
   }

   getRace(id: Signal<string>): Signal<Race | undefined> {
      return computed(() => this.allRaces().find(s => s.id === id()));
   }

   getSeriesRaces(id: Signal<string>): Signal<Race[]> {
      return computed(() => this.allRaces().filter(s => s.seriesId === id()));
   }

   // Fallback fetch for a specific series if not in cache
   async getSeriesById(id: string): Promise<Series | undefined> {
      const currentSeries = this.allSeries().find(s => s.id === id);
      if (currentSeries) {
         return currentSeries;
      }

      // Fallback to fetching directly from Firestore
      const seriesDocRef = this.ref(id);
      const snapshot = await getDoc(seriesDocRef);
      return snapshot.exists() ? { ...snapshot.data(), id: snapshot.id } : undefined;
   }

   // Fallback fetch for a specific race if not in cache
   async getRaceById(id: string): Promise<Race | undefined> {
      const currentRace = this.allRaces().find(r => r.id === id);
      if (currentRace) {
         return currentRace;
      }

      // Fallback to fetching directly from Firestore
      const raceDocRef = this.raceRef(id);
      const snapshot = await getDoc(raceDocRef);
      return snapshot.exists() ? { ...snapshot.data(), id: snapshot.id } : undefined;
   }

   /**
    * Fetches all races for a series directly from Firestore.
    */
   async getSeriesRacesById(seriesId: string): Promise<Race[]> {
      const q = query(this.racesCollection, where('seriesId', '==', seriesId), where('status', '!=', 'Archived'));
      const snapshot = await getDocs(q);
      return snapshot.docs.map(doc => ({ ...doc.data(), id: doc.id })).sort(sortRaces);
   }

   /** Adds races to a specified series 
    *  Race indices and race-of-day are set based on date. 
   */
   async addRaces(seriesDetails: RaceSeriesDetails, races: Partial<Race>[]): Promise<void> {
      const existingRaces = this.allRaces().filter(r => r.seriesId === seriesDetails.id);

      // Create temporary IDs for sorting purposes for new races
      const newRacesWithIds = races.map((race, i) => ({ ...race, id: `new-${i}` })) as Race[];

      const allRacesForSeries = [...existingRaces, ...newRacesWithIds].sort(sortRaces);

      const batch = writeBatch(this.firestore);
      let dayCounter = 0;
      let lastDate: Date | null = null;

      allRacesForSeries.forEach((race, i) => {
         // Recalculate raceOfDay
         if (lastDate && isSameDay(race.scheduledStart, lastDate)) {
            dayCounter++;
         } else {
            dayCounter = 1;
         }
         lastDate = race.scheduledStart;

         const updatedRace: Partial<Race> = {
            ...race,
            index: i + 1,
            raceOfDay: dayCounter,
         };

         if (race.id.startsWith('new-')) {
            // This is a new race, add it to the batch
            const newId = generateSecureID(10000, `R-${seriesDetails.name}`);
            const newRaceRef = this.raceRef(newId);
            // Exclude the temporary id from the data being set
            const { id, ...raceData } = updatedRace;

            batch.set(newRaceRef, {
               ...raceData,
               seriesId: seriesDetails.id,
               seriesName: seriesDetails.name,
               status: 'Future',
            } as Partial<Race>);
         } else {
            // This is an existing race, update it in the batch
            const raceRef = this.raceRef(race.id);
            batch.update(raceRef, { index: updatedRace.index, raceOfDay: updatedRace.raceOfDay });
         }
      });

      // Update series dates
      if (allRacesForSeries.length > 0) {
         const dates = allRacesForSeries.map(r => r.scheduledStart.getTime());
         const startDate = new Date(Math.min(...dates));
         const endDate = new Date(Math.max(...dates));
         batch.update(this.ref(seriesDetails.id), { startDate, endDate });
      }

      await batch.commit();
   }

   /** Delete a race from a series, renumnbering the races are requied */
   override async deleteRace(raceToDelete: Race): Promise<void> {
      const remainingRaces = this.allRaces()
         .filter(r => r.seriesId === raceToDelete.seriesId && r.id !== raceToDelete.id)
         .sort(sortRaces);

      const batch = writeBatch(this.firestore);

      // First, delete the race
      batch.delete(this.raceRef(raceToDelete.id));

      // Then, update the indexes of the remaining races
      let dayCounter = 0;
      let lastDate: Date | null = null;
      remainingRaces.forEach((race, i) => {
         if (lastDate && isSameDay(race.scheduledStart, lastDate)) { dayCounter++; } else { dayCounter = 1; }
         lastDate = race.scheduledStart;
         const raceRef = this.raceRef(race.id);
         batch.update(raceRef, { index: i + 1, raceOfDay: dayCounter });
      });

      // Update series dates
      if (remainingRaces.length > 0) {
         const dates = remainingRaces.map(r => r.scheduledStart.getTime());
         const startDate = new Date(Math.min(...dates));
         const endDate = new Date(Math.max(...dates));
         batch.update(this.ref(raceToDelete.seriesId), { startDate, endDate });
      } else {
         batch.update(this.ref(raceToDelete.seriesId), { startDate: null, endDate: null });
      }

      await batch.commit();
   }

   /** Update a race and recalculate series dates if scheduledStart changed */
   override async updateRace(raceId: string, data: Partial<Race>): Promise<void> {
      const batch = writeBatch(this.firestore);
      batch.set(this.raceRef(raceId), data, { merge: true });

      if (data.scheduledStart) {
         const race = this.allRaces().find(r => r.id === raceId);
         if (race) {
            const allRacesForSeries = this.allRaces().filter(r => r.seriesId === race.seriesId);
            const updatedRaces = allRacesForSeries.map(r => r.id === raceId ? { ...r, ...data } as Race : r);

            const dates = updatedRaces.map(r => r.scheduledStart.getTime());
            if (dates.length > 0) {
               const startDate = new Date(Math.min(...dates));
               const endDate = new Date(Math.max(...dates));
               batch.update(this.ref(race.seriesId), { startDate, endDate });
            }
         }
      }

      await batch.commit();
   }
}

import { inject, Injectable } from '@angular/core';
import { generateSecureID } from 'app/shared/firebase/firestore-helper';
import { deleteDoc, getDocs, getFirestore, query, setDoc, where, writeBatch, Firestore } from '@angular/fire/firestore';
import { Race } from '../model/race';
import { Series } from '../model/series';
import { FirestoreTenantService } from 'app/club-tenant';

export interface RaceSeriesDetails {
  id: string;
  name: string;
  fleetId: string;
}

@Injectable({
  providedIn: 'root',
})
export class RaceCalendarStoreBase {
  protected readonly firestore = inject(Firestore);
  private readonly tenant = inject(FirestoreTenantService);

  protected ref = (id: string) => this.tenant.docRef<Series>('series', id);
  protected seriesCollection = this.tenant.collectionRef<Series>('series');

  protected raceRef = (id: string) => this.tenant.docRef<Race>('races', id);
  protected racesCollection = this.tenant.collectionRef<Race>('races');

  /** Add a series retruning a document Id */
  async addSeries(series: Partial<Series>): Promise<string> {
    series.archived = false;
    const id = generateSecureID(1000, `S-${series.name}`);
    await setDoc(this.ref(id), series);
    return id;
  }

  async updateSeries(id: string, data: Partial<Series>) {
    const scoringCriticalFields: (keyof Series)[] = [
      'scoringAlgorithm',
      'entryAlgorithm',
      'initialDiscardAfter',
      'subsequentDiscardsEveryN',
      'primaryScoringConfiguration',
      'secondaryScoringConfigurations'
    ];

    const hasScoringChange = scoringCriticalFields.some(field => field in data);
    if (hasScoringChange) {
      data.dirty = true;
    }

    await setDoc(this.ref(id), data, { merge: true });
  }

  async deleteSeries(id: string) {
    // Delete races for the series. 
    const racesSnapshot = await getDocs(query(this.racesCollection, where('seriesId', '==', id)));

    const batch = writeBatch(this.firestore);
    racesSnapshot.forEach(doc => batch.delete(doc.ref));

    // Delete the series in the batch
    batch.delete(this.ref(id));
    await batch.commit();
  }

  async addRace(seriesDetails: RaceSeriesDetails, race: Partial<Race>): Promise<void> {
    race.seriesId = seriesDetails.id;
    race.seriesName = seriesDetails.name;
    race.fleetId = seriesDetails.fleetId;
    race.status = 'Future';
    const id = generateSecureID(10000, `R-${seriesDetails.name}`);
    await setDoc(this.raceRef(id), race);
  }

  async updateRace(raceId: string, data: Partial<Race>): Promise<void> {
    await setDoc(this.raceRef(raceId), data, { merge: true });
  }

  async deleteRace(race: Race): Promise<void> {
    await deleteDoc(this.raceRef(race.id));
  }
}

export function seriesSort(a: Series, b: Series): number {
  if (!a.startDate) {
    return !b.startDate ? 1 : 0;
  }

  if (!b.startDate) {
    return -1;
  }

  const ret = a.startDate.getTime() - b.startDate.getTime();
  if (ret !== 0) {
    return ret;
  } else {
    return a.name.localeCompare(b.name);
  }
}

export function sortRaces(a: Race, b: Race): number {
  const ret = a.scheduledStart.getTime() - b.scheduledStart.getTime();

  if (ret === 0) {
    return a.raceOfDay - b.raceOfDay;
  } else {
    return ret;
  }
}

import { inject, Injectable } from '@angular/core';
import { SeriesEntryStore } from './series-entry-store';
import { RaceCompetitorStore } from './race-competitor-store';
import { Handicap, getHandicapValue } from 'app/scoring/model/handicap';
import { PersonalHandicapBand } from 'app/scoring/model/personal-handicap';
import { ScoreSmarterError } from 'app/shared/utils/scoresmarter-error';
import { RaceCompetitor } from '../model/race-competitor';
import { SeriesEntry } from '../model/series-entry';
import {
  PerHullIdentity,
  describeIdentity,
  findCollidingEntry,
} from './series-entry-identity';

/**
 * Per-race overrides are now intentionally minimal. Only `crew` may differ
 * between races for the same hull (handled via `RaceCompetitor.crewOverride`).
 * Every other piece of identity / boat / handicap data lives on the
 * `SeriesEntry` and is therefore inherently series-wide.
 */
export type CrewEditScope = 'raceOnly' | 'wholeSeries';

export type EditOperation =
  | { type: 'setHelm'; value: string }
  | { type: 'setCrew'; value: string; scope: CrewEditScope }
  | { type: 'setBoatClass'; value: string }
  | { type: 'setSailNumber'; value: number }
  | { type: 'setHandicap'; scheme: Handicap['scheme']; value: number }
  | { type: 'setPersonalHandicapBand'; band: PersonalHandicapBand | undefined }
  | { type: 'deleteCompetitor' };

export interface EditRaceCompetitorCommand {
  competitorId: string;
  operation: EditOperation;
}

/**
 * Applies edit commands originating from the per-race UI. Logic intentionally
 * isolates per-race scope (only the crew field) from per-hull scope (everything
 * else); see `EditOperation` for the strict allowed shapes.
 */
@Injectable({ providedIn: 'root' })
export class RaceCompetitorEditService {
  private readonly competitors = inject(RaceCompetitorStore);
  private readonly seriesEntries = inject(SeriesEntryStore);

  async apply(command: EditRaceCompetitorCommand): Promise<void> {
    const target = this.competitors.selectedCompetitors().find(c => c.id === command.competitorId);
    if (!target) {
      throw new Error(`Competitor not found: ${command.competitorId}`);
    }
    const entry = this.seriesEntries.selectedEntries().find(e => e.id === target.seriesEntryId);
    if (!entry) {
      throw new Error(`SeriesEntry ${target.seriesEntryId} not found for competitor ${target.id}`);
    }

    switch (command.operation.type) {
      case 'deleteCompetitor':
        await this.deleteCompetitor(target);
        return;
      case 'setCrew':
        await this.applyCrew(target, entry, command.operation);
        return;
      case 'setHelm':
      case 'setBoatClass':
      case 'setSailNumber':
      case 'setHandicap':
      case 'setPersonalHandicapBand':
        await this.applyEntryChange(entry, command.operation);
        return;
    }
  }

  private async applyCrew(
    target: RaceCompetitor,
    entry: SeriesEntry,
    op: Extract<EditOperation, { type: 'setCrew' }>,
  ): Promise<void> {
    const trimmed = op.value.trim();
    if (op.scope === 'raceOnly') {
      // crewOverride === undefined means "use entry crew"; we keep the empty
      // string as an explicit override that clears the entry crew for this race.
      const next = trimmed === (entry.crew ?? '') ? undefined : trimmed;
      if ((target.crewOverride ?? null) === (next ?? null)) return;
      await this.competitors.updateResult(target.id, { crewOverride: next });
      return;
    }

    if ((entry.crew ?? '') !== trimmed) {
      await this.seriesEntries.updateEntry(entry.id, { crew: trimmed });
    }
    // Wholeseries: drop any per-race overrides for this entry that now match
    // the new entry crew. We deliberately do NOT touch overrides that still
    // diverge from the new entry crew.
    const allForEntry = this.competitors.selectedCompetitors().filter(c => c.seriesEntryId === entry.id);
    for (const comp of allForEntry) {
      if (comp.crewOverride !== undefined && comp.crewOverride === trimmed) {
        await this.competitors.updateResult(comp.id, { crewOverride: undefined });
      }
    }
  }

  private async applyEntryChange(
    entry: SeriesEntry,
    op: Exclude<EditOperation, { type: 'setCrew' | 'deleteCompetitor' }>,
  ): Promise<void> {
    // setHelm / setBoatClass / setSailNumber rewrite the per-hull identity
    // tuple and could collide with another existing SeriesEntry. Guard against
    // that here so we never break the "one entry per (helm, class, sail)"
    // invariant via a rename - the user must resolve the duplicate first.
    if (op.type === 'setHelm' || op.type === 'setBoatClass' || op.type === 'setSailNumber') {
      this.assertRenameDoesNotCollide(entry, op);
    }

    const update: Partial<SeriesEntry> = {};
    switch (op.type) {
      case 'setHelm':
        if (entry.helm === op.value) return;
        update.helm = op.value;
        break;
      case 'setBoatClass':
        if (entry.boatClass === op.value) return;
        update.boatClass = op.value;
        break;
      case 'setSailNumber':
        if (entry.sailNumber === op.value) return;
        update.sailNumber = op.value;
        break;
      case 'setHandicap': {
        const current = getHandicapValue(entry.handicaps, op.scheme);
        if (current === op.value) return;
        const without = (entry.handicaps ?? []).filter(h => h.scheme !== op.scheme);
        update.handicaps = [...without, { scheme: op.scheme, value: op.value }];
        break;
      }
      case 'setPersonalHandicapBand':
        if ((entry.personalHandicapBand ?? null) === (op.band ?? null)) return;
        update.personalHandicapBand = op.band;
        break;
    }
    if (Object.keys(update).length > 0) {
      await this.seriesEntries.updateEntry(entry.id, update);
    }
  }

  /**
   * Throws if applying `op` to `entry` would produce a per-hull identity that
   * already exists on a different SeriesEntry in the same series. Excludes
   * the entry being edited itself so a no-op rename is allowed.
   */
  private assertRenameDoesNotCollide(
    entry: SeriesEntry,
    op: Extract<EditOperation, { type: 'setHelm' | 'setBoatClass' | 'setSailNumber' }>,
  ): void {
    const next: PerHullIdentity = {
      helm: op.type === 'setHelm' ? op.value : entry.helm,
      boatClass: op.type === 'setBoatClass' ? op.value : entry.boatClass,
      sailNumber: op.type === 'setSailNumber' ? op.value : entry.sailNumber,
    };
    const sameSeries = this.seriesEntries
      .selectedEntries()
      .filter(e => e.seriesId === entry.seriesId);
    const collision = findCollidingEntry(sameSeries, next, entry.id);
    if (collision) {
      throw new ScoreSmarterError(
        `Cannot rename: another series entry already exists for ` +
        `${describeIdentity(next)} (id ${collision.id}). ` +
        `Delete or merge that entry before renaming.`,
      );
    }
  }

  private async deleteCompetitor(target: RaceCompetitor): Promise<void> {
    await this.competitors.deleteResult(target.id);
    // If no other RaceCompetitor still references the SeriesEntry, drop the
    // entry too so it doesn't haunt the series with a phantom DNC row.
    const stillReferenced = this.competitors
      .selectedCompetitors()
      .some(c => c.id !== target.id && c.seriesEntryId === target.seriesEntryId);
    if (!stillReferenced) {
      await this.seriesEntries.deleteEntry(target.seriesEntryId);
    }
  }
}

